window.__LIBQ=window.__LIBQ||{};window.__LIBQ["the-gioi-hoan-my"]=window.__LIBQ["the-gioi-hoan-my"]||{};window.__LIBQ["the-gioi-hoan-my"]["q01"]=window.__LIBQ["the-gioi-hoan-my"]["q01"]||{};window.__LIBQ["the-gioi-hoan-my"]["q01"]["artifacts"]={"updatedAt":"2026-07-02","count":142,"artifacts":[{"id":"cot-bong-xuong-cu-thu","name":"Cốt bổng (gậy xương cự thú)","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"Phàm","soHuu":[],"trangThai":"dang-co","blurb":"Gậy lớn mài từ xương cự thú, trai tráng Thạch Thôn dùng để rèn luyện và săn bắn.","detail":"Cốt bổng được mài từ xương của cự thú, là vũ khí trai tráng Thạch Thôn sử dụng khi rèn luyện cũng như đi săn.","nguon":["@c0001"]},{"id":"dai-kiem-kim-loai-den","name":"Đại kiếm kim loại đen","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"Phàm","soHuu":["Thạch Lâm Hổ"],"trangThai":"dang-co","blurb":"Đại kiếm rèn từ kim loại màu đen, khi múa tiếng gió nổi như sấm; kiếm của Thạch Lâm Hổ nặng hơn ba trăm cân.","detail":"Đại kiếm rèn từ kim loại màu đen; trai tráng múa lên tiếng gió nổi như sấm. Đại kiếm của Thạch Lâm Hổ nặng hơn ba trăm cân, đeo sau lưng.","nguon":["@c0001"]},{"id":"sua-thu-bach-thu","name":"Sữa thú (sữa bách thú)","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"Phàm","soHuu":["Thạch Vân Phong"],"trangThai":"dang-co","blurb":"Sữa của trăm loài thú do Thạch Vân Phong nấu, dùng nuôi chú nhóc mồ côi.","detail":"Sữa bách thú do Thạch Vân Phong nấu, thi thoảng bỏ thêm dược thảo, dùng nuôi chú nhóc mồ côi mất cha mẹ từ nửa tuổi.","nguon":["@c0001"]},{"id":"thit-tho-long","name":"Thịt Thổ Long","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"Phàm","soHuu":[],"trangThai":"dang-co","blurb":"Món thịt hiếm có trong bát của lũ trẻ Thạch Thôn.","detail":"Thịt Thổ Long là loại thức ăn có thịt hiếm hoi trong khẩu phần ăn thiếu thốn của lũ trẻ Thạch Thôn.","nguon":["@c0001"]},{"id":"mieng-ngoc-cot-ky-di","name":"Miếng ngọc cốt kỳ dị","category":"khac","categoryLabel":"Vật phẩm bí ẩn","phamCap":"Chưa rõ","soHuu":["Thạch Vân Phong"],"trangThai":"dang-co","blurb":"Miếng ngọc cốt Thạch Vân Phong cất trong ngực áo, lai lịch bí ẩn.","detail":"Miếng ngọc cốt kỳ dị Thạch Vân Phong cất trong ngực áo. Lão sờ tới nó với ánh mắt lộ ánh sáng khác thường khi nói về tương lai của lũ trẻ, gợi ý vật này có lai lịch và bí mật quan trọng.","nguon":["@c0002"]},{"id":"cot-bong","name":"Cốt bổng","cn":"","category":"khac","categoryLabel":"Vũ khí","phamCap":"Phàm khí","soHuu":[],"trangThai":"dang-co","blurb":"Cây gậy lớn mài từ xương cự thú do trai tráng Thạch Thôn dùng khi rèn luyện và săn bắn.","detail":"Cốt bổng là vũ khí thô sơ mài từ xương của cự thú, do các trai tráng vạm vỡ trong Thạch Thôn sử dụng — phản ánh hoàn cảnh sinh tồn khốc liệt nơi mãng sơn, vũ khí làm từ vật liệu săn được trong tự nhiên.","nguon":["@c0001"]},{"id":"sua-bach-thu","name":"Sữa bách thú","cn":"","aliases":["Sữa thú nấu dược thảo"],"category":"khac","categoryLabel":"Thực phẩm/Dưỡng chất","phamCap":"Phàm phẩm","soHuu":["Chú nhóc Thạch Thôn"],"trangThai":"dang-co","blurb":"Chất lỏng trắng nấu trong ang gốm bỏ thêm dược thảo, nuôi lớn chú nhóc mồ côi của Thạch Thôn.","detail":"Sữa bách thú là sữa thú được nấu trong ang gốm, bỏ thêm dược thảo cho bổ dưỡng. Lão tộc trưởng Thạch Vân Phong dùng nó nuôi đứa trẻ mồ côi mất cha mẹ từ nửa tuổi; tới hơn một năm tuổi đứa bé vẫn chưa cai sữa.","nguon":["@c0001"]},{"id":"huyet-tinh","name":"Huyết tinh","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Phàm phẩm","soHuu":["Thạch Thôn"],"trangThai":"dang-co","blurb":"Thuốc đại bổ máu huyết quý giá lấy từ tinh huyết hung thú.","detail":"Tinh huyết chảy ra từ phần đặc biệt trên cơ thể hung thú, được trai tráng Thạch Thôn hứng vào vò đất nung khi mổ xẻ cự thú. Là thuốc đại bổ máu huyết tuyệt vời, quá nửa dùng trên người đám trẻ để rèn da thịt rắn chắc.","nguon":["@c0003"]},{"id":"chan-huyet-ty-huu","name":"Chân huyết Tỳ Hưu","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Trân phẩm","soHuu":["Thạch Thôn"],"trangThai":"dang-co","blurb":"Chân huyết quý còn ẩn trong con Tỳ Hưu hậu duệ, dược tính cực mạnh.","detail":"Tỳ Hưu là hậu duệ kém vương tộc huyết mạch thuần tịnh nhưng còn ẩn một phần chân huyết, quý nhất trong các hung thú; hơn hai năm Thạch Thôn mới bẫy được một con. Phần chân huyết ấy có dược tính cực mạnh, giá trị cực lớn.","nguon":["@c0003"]},{"id":"chan-huyet-hoa-te-hai-dau","name":"Chân huyết Hỏa Tê hai đầu","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Trân phẩm","soHuu":["Thạch Thôn"],"trangThai":"dang-co","blurb":"Chân huyết đỏ rực trích từ dưới sừng Hỏa Tê hai đầu, dược tính không thua Tỳ Hưu.","detail":"Một lão gia mổ chân huyết trong máu thịt cứng dưới sừng con Hỏa Tê hai đ��u; dòng máu hóa thành một quầng sáng đỏ tạo hình con Hỏa Tê nhỏ bằng bàn tay phẫn nộ rít gào. Dược tính không thua chân huyết Tỳ Hưu.","nguon":["@c0003"]},{"id":"sung-rong","name":"Sừng rồng","aliases":["sừng voi sừng rồng"],"category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Trân phẩm","soHuu":["Thạch Thôn"],"trangThai":"dang-co","blurb":"Cặp sừng rồng mọc nhiều năm trên đầu voi sừng rồng, là thuốc báu bổ cốt khó kiếm.","detail":"Cặp sừng rồng mọc lâu năm trên đầu con voi sừng rồng, là thuốc bổ cốt quý hiếm. Thạch Vân Phong dặn trai tráng cẩn thận cưa sừng rồng để không phí của báu.","nguon":["@c0003"]},{"id":"gan-quy-thu-mot-chan","name":"Gân Quỳ Thú một chân","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Phàm phẩm","soHuu":["Thạch Thôn"],"trangThai":"dang-co","blurb":"Sợi gân dai bền của Quỳ Thú một chân, rìu chém mãi không đứt.","detail":"Gân của con Quỳ Thú một chân là sợi gân dai bền, rìu chém mãi không đứt, được Thạch Thôn thu thập làm nguyên liệu quý khi mổ xẻ hung thú.","nguon":["@c0003"]},{"id":"mau-hai-canh-phi-mang","name":"Máu hai cánh Phi Mãng","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Phàm phẩm","soHuu":["Thạch Thôn"],"trangThai":"dang-co","blurb":"Máu quý nằm ở hai cánh con Phi Mãng.","detail":"Máu quý của con Phi Mãng tập trung ở hai cánh, được Thạch Thôn thu thập trong buổi mổ xẻ hung thú sau săn bắn.","nguon":["@c0003"]},{"id":"nuoc-tam-thuoc","name":"Nước tắm thuốc","category":"dan-duoc","categoryLabel":"Dược dịch","soHuu":["Thạch Thôn"],"trangThai":"da-dung","blurb":"Dược dịch tắm thuốc của Thạch Thôn dùng tăng cường thể chất lũ trẻ.","detail":"Chế trong tám đỉnh đồng lớn từ dược thảo, rết dài vài thược, nhện to bằng nắm tay, chân huyết hung thú, xương cánh Phi Mãng và xương chân Quỳ Thú, nước đen kịt như mực. Làm gân cốt trẻ con cường tráng sánh ngang cự thú nhưng chưa đến mức thoát thai hoán cốt; tắm vào da thịt như dao cắt, trẻ con kêu gào thảm thiết.","nguon":["@c0004"]},{"id":"thuoc-bot-tri-thuong","name":"Thuốc bột trị thương","category":"dan-duoc","categoryLabel":"Bảo dược","soHuu":["Thạch Thôn"],"trangThai":"da-dung","blurb":"Bảo dược trị thương của Thạch Thôn chế từ nước thuốc thừa.","detail":"Vì chân huyết quý hiếm nên các bô lão không nỡ để phí, đun cạn nước thuốc tắm thừa rồi thêm dược thảo đặc biệt chế thành thuốc b���t; vừa là thuốc bổ vừa là bảo dược trị thương mang theo đi săn cứu mạng.","nguon":["@c0004"]},{"id":"bao-duoc-dac-biet","name":"Bảo dược đặc biệt","category":"dan-duoc","categoryLabel":"Đan dược","soHuu":["Thạch Vân Phong","Nhóc tỳ"],"trangThai":"da-dung","blurb":"Bảo dược Thạch Vân Phong chế riêng cho nhóc tỳ ăn để bồi bổ thể chất.","detail":"Chế từ đoạn quý nhất trên sừng voi sừng rồng, xương móng vuốt Tỳ Hưu, sừng đỏ Hỏa Tê (mài bột), trộn chân huyết hung thú, nấu trong sữa thú thêm thảo dược kì dị thành chất lỏng đặc sệt thơm đậm. Nhóc tỳ ăn hết khiến dược kình phát tác cực mạnh, nổi cơn quậy phá; cốt văn lan rộng, thể chất tăng mạnh.","nguon":["@c0004"]},{"id":"chuy-tu-kim","name":"Chùy Tử Kim","category":"khac","categoryLabel":"Công cụ","soHuu":["Thạch Vân Phong"],"trangThai":"dang-co","blurb":"Chùy Thạch Vân Phong dùng đập vỡ vật liệu quý khi chế bảo dược.","detail":"Công cụ dùng để đập đoạn quý nhất trên sừng voi sừng rồng khi Thạch Vân Phong chế bảo dược cho nhóc tỳ.","nguon":["@c0004"]},{"id":"hai-chiec-binh-dac-biet","name":"Hai chiếc bình đặc biệt","category":"khac","categoryLabel":"Vật chứa","soHuu":["Thạch Vân Phong"],"trangThai":"da-dung","blurb":"Hai bình chứa của tộc trưởng dùng trong tắm thuốc đặc biệt cho nhóc tỳ.","detail":"Tộc trưởng mở hai bình: bình thứ nhất phóng làn mây đỏ ngưng thành con Tỳ Hưu dài bằng bàn tay hung dữ; bình thứ hai phóng con tê giác hai đầu đỏ rực. Cả hai bị Thạch Vân Phong vỗ tan thành huyết dịch rơi vào hắc đỉnh của nhóc tỳ.","nguon":["@c0004"]},{"id":"thuoc-tam","name":"Thuốc tắm","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Phương thuốc cổ Thạch Thôn","soHuu":["Thạch Thôn"],"trangThai":"da-dung","blurb":"Nước thuốc đen kịt nấu trong đỉnh đồng để tắm cho trẻ con Thạch Thôn.","detail":"Pha từ dược thảo, rết dài vài thược, nhện to bằng nắm tay khiến nước đen kịt như mực, thêm chân huyết đỏ tươi cùng xương cánh Phi Mãng và xương chân Quỳ Thú đập nát. Tăng cường gân cốt cho trẻ con, khiến chúng bong da cũ từng mảng và khỏe hơn rõ rệt sau một đêm, dù chưa đến mức thoát thai hoán cốt.","nguon":["@c0004"]},{"id":"chan-huyet-hung-thu","name":"Chân huyết hung thú","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Quý hiếm","soHuu":["Thạch Thôn"],"trangThai":"da-dung","blurb":"Chút huyết quý giá lấy từ hung thú săn được, dùng tắm thuốc tăng cường thể chất.","detail":"Huyết đỏ tươi lấy từ cơ thể hung thú săn được, cực kỳ quý giá trong hoàn cảnh khốc liệt của Đại Hoang nên không nỡ phí chút nào. Rót vào nước thuốc giúp tăng cường thể chất cho cả trẻ con lẫn người lớn; cũng là thành phần trong lô bảo dược riêng của nhóc tỳ.","nguon":["@c0004"]},{"id":"lo-bao-duoc-rieng","name":"Lô bảo dược riêng cho nhóc tỳ","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Dược kình cực mạnh","soHuu":["Thạch Vân Phong","Nhóc tỳ"],"trangThai":"da-dung","blurb":"Lô bảo dược Thạch Vân Phong tự nấu riêng cho nhóc tỳ, dược kình cực mạnh.","detail":"Thạch Vân Phong nấu từ đoạn quý nhất trên sừng voi sừng rồng (đập bằng chùy Tử Kim), xương móng vuốt Tỳ Hưu và sừng đỏ Hỏa Tê mài bột, trộn chân huyết bỏ vào nồi sữa thú cùng thảo dược kỳ dị, nấu thành chất sệt thơm ngào ngạt. Dược kình quá mạnh khiến nhóc tỳ sau khi ăn hết nồi thì mắt đỏ au, quậy phá hai canh giờ; thể chất-tốc độ-sức mạnh tăng nhiều và cốt văn lan rộng lên cả cánh tay.","nguon":["@c0004"]},{"id":"dinh-dong-ngan-can","name":"Đỉnh đồng ngàn cân","cn":"","aliases":[],"category":"khac","categoryLabel":"Khí vật luyện lực","phamCap":"Phàm vật","soHuu":["Thạch Thôn"],"trangThai":"dang-co","blurb":"Chiếc đỉnh đồng nặng cả ngàn cân đặt giữa sân Thạch Thôn, dùng để thử sức nâng đỉnh của lũ trẻ.","detail":"Đỉnh đồng nặng cả ngàn cân, hoa văn chim bay thú chạy cổ xưa, vách dày, chân đỉnh nhẵn bóng như gương, bề mặt khắc hoa văn chu tước. Trong chương, đám trẻ Thạch Thôn thi nhau nâng đỉnh: Thạch Đại Tráng chín tuổi nâng qua đầu thành công, còn Thạch Hạo ba tuổi rưỡi ngồi sụp nâng đáy đỉnh, nhấc bổng qua chỏm đầu.","nguon":["@c0005"]},{"id":"huyet-duoc","name":"Huyết dược","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Không rõ","soHuu":["Thạch Vân Phong"],"trangThai":"dang-co","blurb":"Tinh hoa chưng cất từ máu mãnh thú qua cốt văn, dùng cho tẩy lễ.","detail":"Được Thạch Vân Phong chưng cất từ máu các mãnh thú có linh tính bằng cốt văn. Mỗi con thú cuối cùng chỉ còn một giọt máu lung linh trong suốt rực rỡ như kim cương màu máu, chảy vào bình ngọc. Chỉ chân huyết phẩm chất cao mới có tác dụng; dùng chuẩn bị tẩy lễ cho Thạch Hạo.","nguon":["@c0006"]},{"id":"tuong-qua","name":"Tương Quả","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Thường","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Quả đỏ au thơm lừng, món Thạch Hạo thích ăn nhất.","detail":"Loại quả đỏ au thơm lừng, căng mọng như viên mã não, là món Thạch Hạo thích ăn nhất, do Thạch Lâm Hổ hái tặng sau khi đội săn trở về.","nguon":["@c0006"]},{"id":"trung-thanh-lan-ung","name":"Trứng Thanh Lân Ưng","category":"khac","categoryLabel":"Trứng dị cầm","phamCap":"Chưa rõ","soHuu":[],"trangThai":"dang-co","blurb":"Ba quả trứng của dị cầm Thanh Lân Ưng, óng ánh như bích ngọc, mang tiềm năng huyết dịch Thái Cổ Ma Cầm.","detail":"Ba quả trứng đặt trong Ngô Sào trên lớp Kim Ti Thảo, mỗi quả to bằng chậu nước, xanh biếc như mã não, có đường vằn và chấm li ti. Đây là trứng của Thanh Lân Ưng — dị cầm hung hãn mang huyết dịch truyền thừa từ Thái Cổ Ma Cầm. Đám trẻ Thạch Thôn phát hiện và định mang về thôn ấp.","nguon":["@c0007"]},{"id":"kim-ti-thao","name":"Kim Ti Thảo","category":"nguyen-lieu","categoryLabel":"Cỏ linh","phamCap":"Chưa rõ","soHuu":[],"trangThai":"dang-co","blurb":"Loại cỏ mềm mại được Thanh Lân Ưng trải trong tổ để ấp trứng.","detail":"Cỏ mềm mại thoải mái được trải bên trong Ngô Sào của Thanh Lân Ưng, làm nền lót cho ba quả trứng dị cầm.","nguon":["@c0007"]},{"id":"vay-thanh-lan-ung","name":"Vảy Thanh Lân Ưng","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Tấm vảy kim loại hung cầm to bằng bàn tay trẻ sơ sinh, sắc lẻm hàn quang.","detail":"Vảy hung cầm trưởng thành lót trong tổ Thanh Lân Ưng, sắc lẻm tỏa hàn quang lấp lóa, cứng đến mức đại kiếm mấy trăm cân cũng khó chém đứt. Thạch Đại Tráng dẫm phải bị đâm thủng đế giày tóe máu chân; Thạch Hạo thu mấy tấm mang về.","nguon":["@c0008"]},{"id":"to-khi-cuc-xuong-tay-hung-thu","name":"Tổ Khí","cn":"","category":"than-khi","categoryLabel":"Bảo khí gia truyền","phamCap":"Bảo khí trấn thôn","soHuu":["Thạch Lâm Hổ","Thạch Vân Phong"],"trangThai":"Đang dùng","blurb":"Bảo khí gia truyền lâu đời của Thạch Thôn dùng để chấn nhiếp hung thú, vốn là một cục xương tay hung thú.","detail":"Tổ Khí là bảo khí gia truyền lâu đời trong Thạch Thôn, hình dạng là một cục xương tay hung thú, dùng để chấn nhiếp cường địch. Khi tế, người dùng thúc giục khiến tay trái nổi cốt văn rực rỡ rồi ấn cục xương lên; cục xương phát ra một luồng hơi thở như vua vạn thú sống lại, khiến hung cầm chấn động bay lên xa. Sau khi kích hoạt, cục xương dung hợp vào cánh tay trái người tế, huyết nhục dung hòa, ngưng thành một phù hiệu cổ xưa như thể hung thú sắp nhảy ra. Trong thôn có ít nhất hai cái Tổ Khí; lần này Thạch Lâm Hổ tế bảo để đẩy lui Thanh Lân Ưng.","nguon":["@c0009"]},{"id":"cung-sung-rong","name":"Cung sừng rồng","cn":"","category":"khac","categoryLabel":"Vũ khí","phamCap":"","soHuu":["Bì Hầu"],"trangThai":"Vũ khí Thạch Thôn","blurb":"Cung cứng làm từ sừng cắt ra từ Long Giác Tượng, nguyên liệu làm cung tốt nhất của Thạch Thôn.","detail":"Cung sừng rồng là loại cung cứng được chế từ sừng cắt ra từ Long Giác Tượng — nguyên liệu làm cung tốt nhất của Thạch Thôn. Cung rất cứng, chỉ người đã trưởng thành mới đủ sức kéo nổi. Trong trận đối đầu, Bì Hầu bắn cung này vào đầu Thanh Lân Ưng nhưng mũi tên chỉ tóe lửa, không xuyên thủng được lớp vẩy xanh cứng như kim loại của hung cầm.","nguon":["@c0009"]},{"id":"thiet-mau","name":"Thiết mâu","cn":"","category":"khac","categoryLabel":"Vũ khí","phamCap":"","soHuu":["Thạch Hạo"],"trangThai":"Vũ khí Thạch Thôn","blurb":"Mâu sắt nặng bốn năm chục cân, vũ khí ném uy lực trong tay các nhóc khỏe của Thạch Thôn.","detail":"Thiết mâu là mâu sắt nặng chừng bốn năm chục cân. Thạch Hạo mượn thiết mâu, lấy đà tăng tốc ném thẳng về mắt Thanh Lân Ưng khiến nó lần đầu lộ vẻ kinh dị; dù né kịp, mâu vẫn làm bong một miếng vẩy ở khóe mắt khiến hung cầm chảy máu. Về sau ba đứa khỏe nhất — Thạch Hạo, Nhị Mãnh, Thạch Đại Tráng — chuyên dùng thiết mâu nhắm vào hai mắt con hung cầm để câu giờ chờ cứu viện.","nguon":["@c0009"]},{"id":"to-khi-da-thu-co","name":"Tổ Khí (thứ hai — da thú cổ)","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Bảo vật","soHuu":["Thạch Phi Giao"],"trangThai":"dang-co","blurb":"Tổ Khí thứ hai của Thạch Thôn — tấm da thú cổ ngưng phù văn.","detail":"Tấm da thú cổ lấm máu khô, được Thạch Phi Giao ấn lên ngực; da thú dung hợp thành da thịt gã, kết thành kí tự thần bí hiện bóng hung thú mơ hồ, ngực như mọc thêm gương mặt thú phát tiếng thú gầm rung núi. Loại hung thú này ngưng sức mạnh ở da thịt thay vì xương.","nguon":["@c0010"]},{"id":"lang-nha-dai-bong","name":"Lang Nha Đại Bổng","category":"khac","categoryLabel":"Binh khí","phamCap":"Binh khí thường","soHuu":["Thạch Phi Giao"],"trangThai":"mat","blurb":"Gậy lớn của Thạch Phi Giao.","detail":"Cây gậy lớn Thạch Phi Giao vốn dùng, bị gã vứt bỏ để rảnh tay tế Tổ Khí thứ hai.","nguon":["@c0010"]},{"id":"hac-thiet-con","name":"Hắc Thiết Côn","category":"khac","categoryLabel":"Binh khí","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Côn đen của sinh vật hình người cao chọc mây (hồi tưởng).","detail":"Cây côn đen của một sinh vật hình người cao chọc mây mà Thạch Phi Giao từng thấy bước qua mấy ngọn núi hai năm trước, thuộc thế lực Thái Cổ chưa lộ diện.","nguon":["@c0010"]},{"id":"trung-vay-tim-phan-to","name":"Quả trứng phản tổ (trứng vảy tím)","category":"khac","categoryLabel":"Trứng linh cầm","phamCap":"Chưa rõ","soHuu":["Thạch Thôn"],"trangThai":"dang-co","blurb":"Quả trứng bị cành liễu già phất qua nên xảy ra phản tổ, kế thừa mảnh ấn ký Thái Cổ Ma Cầm.","detail":"Một trong ba quả trứng của Thanh Lân Ưng, sau khi cành liễu xanh nhạt phất qua thì tỏa hào quang chói lọi, xuất hiện vô số ký hiệu phức tạp như Long Xà, Thần Tước bay trong lửa. Sinh cơ mạnh hơn nhiều lần nhờ Sinh mệnh lạc ấn truyền thừa từ Thái Cổ Ma Cầm hồi phục, huyết mạch cao quý hơn cả bố mẹ. Khi nở, vỏ trứng vỡ nát thành bột phấn, con chim non trên người là vảy tím rực rỡ lấp lánh như lửa đang thiêu đốt, linh tính kinh người, đôi mắt to lóng lánh — một linh cầm rất không bình thường.","nguon":["@c0011"]},{"id":"thuoc-mau-tim","name":"Thuốc màu tím","category":"dan-duoc","categoryLabel":"Đan dược","soHuu":["Thạch Vân Phong"],"trangThai":"da-dung","blurb":"Hai viên thuốc màu tím thơm nức tộc trưởng đựng trong bình ngọc, dùng để trị thương nặng.","detail":"Tộc trưởng Thạch Vân Phong lấy từ bình ngọc hai viên thuốc màu tím thơm nức để cứu Thạch Thủ Sơn: một viên bóp nát xoa lên vết thương, một viên cho uống.","nguon":["@c0013"]},{"id":"thuoc-chan-huyet-hung-thu","name":"Thuốc chân huyết hung thú","category":"dan-duoc","categoryLabel":"Dược liệu","soHuu":["Thạch Lâm Hổ"],"trangThai":"da-dung","blurb":"Thuốc do tộc lão Thạch Thôn nấu từ chân huyết hung thú, dùng sơ cứu vết thương.","detail":"Các tộc lão nấu thuốc bằng chân huyết hung thú cho Thạch Thủ Sơn uống, kèm thuốc lâu năm cắn nát dán lên vết thương để sơ cứu trọng thương.","nguon":["@c0013"]},{"id":"mui-ten-sat-bai-thon","name":"Mũi tên sắt dài một mét ba","category":"khac","categoryLabel":"Vũ khí","soHuu":["Bái Thôn"],"trangThai":"dang-co","blurb":"Tên sắt bóng loáng dài một mét ba, vũ khí chủ lực của Bái Thôn, đủ sức bắn thủng giáp hộ thân.","detail":"Mũi tên sắt dài một mét ba bắn thủng giáp hộ thân Thạch Thủ Sơn, xuyên qua phổi phải ra tới sau lưng. Là vũ khí bắn xuyên giáp ba lớp mà người Bái Thôn dùng tấn công Thạch Thôn.","nguon":["@c0013"]},{"id":"giap-thep-ba-lop","name":"Giáp thép tinh chế ba lớp","category":"khac","categoryLabel":"Phòng cụ","soHuu":["Thạch Thôn"],"trangThai":"hong","blurb":"Giáp thép tinh chế dày ba lớp lót trước ngực người Thạch Thôn, bị thằng nhóc Bái Thôn bắn xuyên toàn bộ.","detail":"Mấy huynh đệ Thạch Thôn trước ngực đều lót ba lớp giáp thép tinh chế dày, nhưng toàn bộ đều bị thằng nhóc Bái Thôn bắn xuyên trong vụ chặn cướp.","nguon":["@c0013"]},{"id":"vang-trang-luoi-liem-van-lac","name":"Vầng trăng lưỡi liềm (văn lạc)","category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Chiêu thức do văn lạc tạo, Thạch Hạo dùng ngón tay hiện văn lạc nắm trong lòng bàn tay.","detail":"Thạch Hạo tạo bằng ngón tay hiện văn lạc, nắm trong lòng bàn tay như một vầng trăng lưỡi liềm nhỏ, vung ra hàng loạt điểm sáng khuếch tán đánh vỡ tên nỏ; hóa thành ánh sáng trong suốt đón đánh Bái Phong khiến hắn phun máu.","nguon":["@c0015"]},{"id":"day-deo-tay-rang-thu","name":"Dây đeo tay mài bằng răng thú","category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Dây đeo trên cổ tay Thạch Hạo, người Bái Thôn lầm tưởng là Bảo Cụ quý hiếm.","detail":"Dây đeo tay mài bằng răng thú trên cổ tay Thạch Hạo. Người Bái Thôn thấy ký hiệu lấp lóe khi Thạch Hạo dùng sức, hét lên đó là Bảo Cụ quý hiếm giúp tăng sức mạnh — thực chất họ hiểu nhầm về sức mạnh Cốt Văn của nó.","nguon":["@c0015"]},{"id":"cung-long-giac","name":"Cung Long Giác","category":"khac","categoryLabel":"Vũ khí","phamCap":"Không rõ","soHuu":["Thạch Thôn"],"trangThai":"dang-co","blurb":"Loại cung mà Bái Thôn giao nộp cho Thạch Thôn làm bồi thường sau khi thua trận.","detail":"Nằm trong số vũ khí Bái Thôn phải giao nộp cùng hàng đống tên sắt và kiếm bản to để chuộc Bái Phong và rút khỏi vùng núi.","nguon":["@c0016"]},{"id":"kiem-ban-to-bai-thon","name":"Kiếm bản to","category":"khac","categoryLabel":"Vũ khí","phamCap":"Không rõ","soHuu":["Thạch Thôn"],"trangThai":"dang-co","blurb":"Kiếm bản to nằm trong số vũ khí Bái Thôn giao nộp làm bồi thường.","detail":"Cùng với tên sắt và cung Long Giác, kiếm bản to được Bái Thôn giao cho Thạch Thôn khi thỏa hiệp bồi thường.","nguon":["@c0016"]},{"id":"chan-huyet-toan-nghe","name":"Chân huyết Toan Nghê","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Chân huyết rút từ thi thể Toan Nghê Thái Cổ Di Chủng để khắc Nguyên Thủy Bảo Phù.","detail":"Vật liệu quý được rút từ thi thể của con Toan Nghê Thái Cổ Di Chủng, dùng để khắc Nguyên Thủy Bảo Phù trên bộ xương như mở kho báu động trời.","nguon":["@c0016"]},{"id":"chan-huyet-bao-cot-toan-nghe","name":"Chân huyết và bảo cốt Toan Nghê","category":"nguyen-lieu","categoryLabel":"Di vật","soHuu":[],"trangThai":"dang-co","blurb":"Di thể của Toan Nghê chứa chân huyết kinh thế cùng ký hiệu nguyên thủy, trở thành kho báu vô chủ.","detail":"Sau khi Toan Nghê già chết đi, toàn bộ chân huyết và bảo cốt của nó trở thành kho báu vô chủ, kèm theo Bảo Thuật cùng ký hiệu nguyên thủy, khiến các thế lực quanh vùng đổ xô vào núi tranh đoạt.","nguon":["@c0018"]},{"id":"bao-the-toan-nghe","name":"Bảo thể Toan Nghê","cn":"","category":"khac","categoryLabel":"Di vật","phamCap":"Thái Cổ Di Chủng","soHuu":[],"trangThai":"Chôn dưới đống đá núi, vừa lộ ra","blurb":"Di thể của Thái Cổ Di Chủng Toan Nghê, nuốt vào sẽ tiến hóa thành bá chủ sơn lâm.","detail":"Bảo thể của Thái Cổ Di Chủng Toan Nghê xuất hiện từ giữa đống đá núi khi cá xấu bạc hất tung cự thạch. Một luồng hào quang vàng như vầng thái dương nhỏ nhô lên — đó là một cái chân phải to bằng cột, cường tráng, mọc đầy lông thú màu vàng lóng lánh như vàng ròng, tràn ngập hung khí. Trên người có ký hiệu nguyên thủy lấp lánh rực rỡ, khiến tất cả sinh linh mạnh mẽ đều chấn động, mắt nóng bỏng và xông về phía trước tranh đoạt. Là mục tiêu tranh đoạt của cả đàn hung thú vì nuốt vào sẽ tiến hóa thành bá chủ sơn lâm.","nguon":["@c0019","@c0018"]},{"id":"chan-thu-mau-vang-toan-nghe","name":"Chân thú màu vàng (bảo thể Toan Nghê)","aliases":["Chân thú màu vàng"],"category":"khac","categoryLabel":"Khác","phamCap":"Thái Cổ Di Chủng","soHuu":[],"trangThai":"dang-co","blurb":"Xác của một con Toan Nghê Thái Cổ Di Chủng chân chính, thân dài sáu mét, toàn thân như vàng ròng, dù đã chết hung khí vẫn lan tỏa.","detail":"Sau khi được đào lộ, bảo thể Toan Nghê trở thành mục tiêu tranh đoạt của cả bầy hung thú hung cầm. Thân dài sáu mét, toàn thân như vàng ròng, chứa bảo huyết quý giá. Bất ngờ con Toan Nghê tưởng đã chết bỗng bật dậy sống lại, xé đứt một cánh tay Ác Ma Viên và đánh gãy sừng Ly Hỏa Ngưu Ma, khiến toàn bộ hung thú kinh sợ ngã rạp.","nguon":["@c0020"]},{"id":"canh-tay-ac-ma-vien","name":"Cánh tay Ác Ma Viên","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Bộ phận Thái Cổ Di Chủng","soHuu":["Thanh Lân Ưng"],"trangThai":"dang-co","blurb":"Cánh tay Ác Ma Viên bị Toan Nghê xé đứt, chứa chân huyết hiếm có.","detail":"Trong đại chiến, Toan Nghê xé đứt một cánh tay của Ác Ma Viên. Cánh tay này chứa chân huyết hiếm có nên được Thanh Lân Ưng tha về Thạch Thôn, dùng cho lễ tẩy năm tuổi của Thạch Hạo.","nguon":["@c0021","@c0031"]},{"id":"sung-ly-hoa-nguu-ma","name":"Sừng Ly Hỏa Ngưu Ma","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Thú bảo vô giá","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Cái sừng đỏ dài mấy mét của Ly Hỏa Ngưu Ma, thú bảo vô giá.","detail":"Sau đại chiến, nhóc tỳ khiêng cái sừng dài mấy mét của Ly Hỏa Ngưu Ma về, được xem là thú bảo vô giá.","nguon":["@c0021"]},{"id":"bao-nguyet-thach-hao","name":"Bảo Nguyệt","aliases":["Bảo Cụ của Thạch Hạo"],"category":"phap-bao","categoryLabel":"Pháp bảo","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Vũ khí hình trăng bạc rất mạnh của Thạch Hạo, chém gãy tên mâu sắt.","detail":"Vũ khí hình vầng trăng bạc do Thạch Hạo triệu hồi, uy lực khiến hơn hai mươi người Bái Thôn không địch nổi. Chém rơi và gãy tên sắt mỗi mũi ngàn cân, chém đứt vai tay đối thủ, chém rách bụng thủ lĩnh đội săn.","nguon":["@c0022"]},{"id":"sung-do-tham-thai-co-di-chung","name":"Sừng đỏ thẫm của Thái Cổ Di Chủng","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Sừng dài mấy mét màu đỏ thẫm, bên trong có bảo huyết.","detail":"Sừng đỏ thẫm dài mấy mét của Thái Cổ Di Chủng, bên trong chứa bảo huyết. Thạch Hạo tin bảo huyết này có tác dụng giải độc như sừng Linh Tê nên chém thịt dính sừng cho Thanh Lân Ưng ăn.","nguon":["@c0022"]},{"id":"vong-rang-thu-bai-thon","name":"Vòng răng thú","category":"khac","categoryLabel":"Khác","soHuu":["Thiếu niên trên cáng (Bái Thôn)"],"trangThai":"dang-co","blurb":"Vật thiếu niên Bái Thôn cầm thưởng thức trên cáng.","detail":"Vòng răng thú mà thiếu niên Bái Thôn nằm trên cáng cầm thưởng thức khi đi cùng viện binh.","nguon":["@c0022"]},{"id":"bao-cu-te-linh-ban","name":"Bảo Cụ do Tế Linh ban","category":"khac","categoryLabel":"Khác","soHuu":["Bái Thôn"],"trangThai":"dang-co","blurb":"Trang bị Tế Linh cấp cho Bái Thôn để đối phó Thạch Hạo.","detail":"Bảo Cụ mà Tế Linh ban cho Bái Thôn lần này để đối phó Thạch Hạo. Các ông già Bái Thôn nói Tế Linh sẽ tự đến vì bảo thể Toan Nghê.","nguon":["@c0022"]},{"id":"bao-cu-bai-phong","name":"Bảo Cụ (của Bái Phong)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Bái Phong"],"trangThai":"Đang sử dụng","blurb":"Bảo Cụ của Bái Phong, phóng ra điểm sáng xán lạn có lực sát thương kinh người.","detail":"Bảo Cụ do thiếu niên thiên tài Bái Phong của Bái Thôn nắm giữ. Khi ra tay, nó phát ra điểm sáng xán lạn xông tới, đánh xuyên sáu bảy người Thạch Thôn và làm rách vai Thạch Hạo, một đốm sáng suýt đâm xuyên yết hầu Thạch Hạo. Bái Phong dùng nó tập kích lạnh lùng, khiến đám đông kinh ngạc vì không ngờ người tu Cốt Văn cũng có thể sử dụng Bảo Cụ. Mưa ánh sáng phóng ra bay như mưa sao băng cắt ngang trời.","nguon":["@c0023"]},{"id":"bao-cu-rang-thu-42","name":"Bảo Cụ răng thú (42 răng thú)","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chí bảo","soHuu":["Thạch Hạo"],"trangThai":"bi-cuop","blurb":"Xâu răng thú trắng như mỡ dê do Bảo cốt Tế Linh làm thành, tụ tán hóa hạt sáng, quái thú, vũ khí, chiến y.","detail":"Xâu 42 răng thú trắng như mỡ dê đá ngọc, do Bảo cốt Tế Linh làm thành, chí bảo của Bái thôn. Có thể tụ tán, hóa thành hạt sáng, mưa sao băng, quái thú sói, vũ khí (chủy thủ, mũi tên) và chiến y. Tế Linh ban cho, khi Tế Linh còn sống thì người được ban không cần Cốt văn cũng dùng được. Ở chương 24, Bái Phong dùng Bảo cụ đâm thủng đá lớn sáu bảy mét như cái sàng, nhưng cuối cùng bị nhóc tỳ đánh bại và cướp mất, đeo lên cổ tay.","nguon":["@c0024"]},{"id":"binh-thuoc-giai-doc-thanh-lan-ung","name":"Bình thuốc giải độc","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Không rõ","soHuu":["Thạch Vân Phong"],"trangThai":"da-dung","blurb":"Bình thuốc Thạch Vân Phong dùng giải độc cho Thanh Lân Ưng.","detail":"Thạch Vân Phong rắc thuốc từ bình lên vết thương để giải độc cho Thanh Lân Ưng đang bị trúng độc.","nguon":["@c0024"]},{"id":"mau-sat-thach-lam-ho","name":"Mâu sắt","category":"linh-khi","categoryLabel":"Vũ khí","phamCap":"Vũ khí thường","soHuu":["Thạch Lâm Hổ"],"trangThai":"Đang sử dụng","blurb":"Cây mâu sắt Thạch Lâm Hổ ném cắm vào con sói biến dị to bằng cái nhà khiến nó bị thương.","detail":"Vũ khí của Thạch Lâm Hổ trong trận vây của đám Sói biến dị. Khi bầy sói to bằng cái nhà, răng nanh dài áp sát, Thạch Lâm Hổ ném cây mâu sắt cắm thẳng vào con sói to làm nó bị trọng thương, cứu người thôn dân đang bị đe dọa.","nguon":["@c0025"]},{"id":"vong-rang-thu-bao-cu","name":"Vòng răng thú (Bảo Cụ)","cn":"","category":"phap-bao","categoryLabel":"Bảo Cụ","phamCap":"","soHuu":["Thạch Hạo"],"trangThai":"Thạch Hạo sử dụng","blurb":"Vòng răng óng ánh như sao mà Thạch Hạo dùng, thực ra là răng của chính con Bái già rụng ra, đã tế luyện trăm lần.","detail":"Một chiếc vòng kết từ răng thú óng ánh như sao, do Thạch Hạo (nhóc tỳ) sử dụng để tấn công con Bái già. Đám răng này thực chất là răng của chính con Bái già rụng ra, đã được tế luyện trăm lần thành bảo cụ. Khi bị dùng làm vũ khí đánh mình, con Bái già nổi giận và lao tới thu hồi.","nguon":["@c0026"]},{"id":"xich-than-rang-xanh","name":"Xích thần ráng xanh","cn":"","category":"phap-bao","categoryLabel":"Thần thông/Pháp bảo","phamCap":"","soHuu":["Tế Linh"],"trangThai":"Tế Linh thi triển","blurb":"Cành non của cây liễu Tế Linh hóa thành một sợi xích thần màu ráng xanh kéo dài hơn một dặm, nhanh như chớp vọt tới tấn công.","detail":"Khi tộc nhân cầu khẩn, cái chồi non của cây liễu Tế Linh cháy đen động đậy, hóa thành một sợi xích thần ráng xanh kéo dài hơn một dặm, nhanh như chớp vọt tới nhắm con Bái dữ chặn đường trước thôn. Là biểu hiện sức mạnh của Tế Linh — thực thể bảo hộ thôn làng dưới hình cây liễu.","nguon":["@c0026"]},{"id":"sung-bao-do-tham-lot-xac","name":"Sừng bảo đỏ thẫm","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":["Thạch Vân Phong"],"trangThai":"dang-co","blurb":"Sừng bảo màu đỏ thẫm dùng trong kế hoạch lột xác của Nhóc tỳ.","detail":"Sừng bảo màu đỏ thẫm được Thạch Vân Phong chuẩn bị để giúp Nhóc tỳ lột xác trước năm tuổi, cùng với chân huyết Toan Nghê và cánh tay Vược Ác Ma.","nguon":["@c0028"]},{"id":"cot-thu","name":"Cốt thư","category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":["Thạch Vân Phong","Thạch Hạo"],"trangThai":"dang-co","blurb":"Mấy bộ sách phù văn tộc trưởng truyền thụ cho Thạch Hạo.","detail":"Mấy bộ sách ghi chép Cốt văn / phù văn mà Thạch Vân Phong truyền lại cho Thạch Hạo, gồm cả phù văn cuối cùng, giúp nhóc tỳ học Cốt văn và đột phá cảnh Thay máu thần tốc.","nguon":["@c0029"]},{"id":"thien-dia-bao-duoc-truyen-thuyet","name":"Thiên địa bảo dược (truyền thuyết)","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Thuốc quý trong truyền thuyết Thạch Hạo hứa hái để chữa ám thương cho tộc trưởng.","detail":"Thiên địa bảo dược cực kỳ hiếm, dù đại tộc mấy triệu dân chưa chắc có. Thạch Hạo hứa sẽ hái được để chữa ám thương cổ quái cho Thạch Vân Phong.","nguon":["@c0029"]},{"id":"xuong-thu-bao-cu-tu-son-toc","name":"Xương thú Bảo Cụ (Tử Sơn Tộc)","cn":"","category":"phap-bao","categoryLabel":"Bảo cụ","phamCap":"","soHuu":["Chú ruột của Tử Sơn Hầu"],"trangThai":"dang-co","blurb":"Xương thú dài sáu bảy mét, hào quang trắng, lấp lóe ký hiệu, bay sát đất, thu nhỏ còn cỡ bàn tay.","detail":"Bảo cụ của Tử Sơn Tộc: một cái xương thú dài sáu bảy mét, tỏa hào quang trắng và lấp lóe ký hiệu, bay sát đất một thước, súc địa thành thốn; khi cất đi thu nhỏ còn cỡ bàn tay. Chở chú ruột Tử Sơn Hầu tới Tiểu Cô Sơn Trấn.","nguon":["@c0030"]},{"id":"da-thu-co-loi-toc","name":"Da thú cổ (Lôi Tộc)","cn":"","category":"phap-bao","categoryLabel":"Bảo cụ","phamCap":"","soHuu":["Thanh niên Lôi Tộc"],"trangThai":"dang-co","blurb":"Tấm da thú cổ lấp lóe ký hiệu, khí tức cổ lão tang thương, bay sát đất, thu nhỏ còn cỡ bàn tay.","detail":"Bảo cụ của Lôi Tộc: một tấm da thú cổ lấp lóe ký hiệu, khí tức cổ lão tang thương, bay sát đất ba thước; khi cất đi thu nhỏ còn cỡ bàn tay. Chở người Lôi Tộc tới Tiểu Cô Sơn Trấn.","nguon":["@c0030"]},{"id":"chan-huyet-toan-nghe-tay-le","name":"Chân huyết Toan Nghê (dịch tẩy lễ)","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Bảo huyết Thái Cổ Di Chủng","soHuu":["Thạch Thôn"],"trangThai":"da-dung","blurb":"Bảo huyết chứa máu hoàng kim của Toan Nghê, dùng thay nước suối làm dịch tẩy lễ cho Thạch Hạo.","detail":"Chân huyết Toan Nghê chứa dịch thể vàng xán lạn, mang sức mạnh thần thánh của Thái Cổ Di Chủng, đặc mà không đông. Được lấy đầy bình bạc rồi đổ vào đỉnh thay nước suối làm dịch tẩy lễ luyện hóa cơ thể nhóc tỳ.","nguon":["@c0031"]},{"id":"tim-chi-bao-toan-nghe","name":"Tim chí bảo Toan Nghê","cn":"","category":"khac","categoryLabel":"Bảo vật","phamCap":"Chí bảo Thái Cổ Di Chủng","soHuu":["Thạch Thôn"],"trangThai":"da-dung","blurb":"Quả tim vàng nhạt to bằng chậu của Toan Nghê, ẩn chứa thần tính, thả vào đỉnh làm dịch hóa kim quang.","detail":"Tộc trưởng dùng đao ngọc đào ra quả tim vàng nhạt to bằng chậu ẩn chứa thần tính, tuôn mưa ánh sáng vàng, đặt vào trong đỉnh làm bảo vật cốt lõi cho tẩy lễ.","nguon":["@c0031"]},{"id":"dinh-den-to-truyen","name":"Đỉnh đen tổ truyền","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Bảo vật tổ truyền","soHuu":["Thạch Thôn"],"trangThai":"dang-co","blurb":"Đỉnh lớn khí tức cổ xưa của Thạch Thôn, khắc nhật nguyệt sơn hà và cảnh Tiên Dân Thượng Cổ lễ bái, dùng luyện chân huyết.","detail":"Đỉnh đen tổ truyền toát khí tức cổ xưa, thân khắc nhật nguyệt sơn hà, điểu thú ngư trùng và cảnh Tiên Dân Thượng Cổ lễ bái. Được đun bằng lửa Hắc Giao Mộc để luyện cổ dược, độc trùng và chân huyết Toan Nghê thành dịch tẩy lễ.","nguon":["@c0031"]},{"id":"sung-do-ly-hoa-nguu-ma","name":"Sừng đỏ Ly Hoa Ngưu Ma","cn":"","category":"khac","categoryLabel":"Bảo vật","phamCap":"Chân huyết thông linh","soHuu":["Thạch Thôn"],"trangThai":"dang-co","blurb":"Sừng đỏ dài mấy mét của Ly Hoa Ngưu Ma, sáng như Mã Não, chứa chân huyết thông linh, chưa được đun.","detail":"Sừng đỏ dài mấy mét sáng như Mã Não, chứa chân huyết thông linh của Ly Hoa Ngưu Ma. Chưa được đun trong tẩy lễ này vì sợ nhóc tỳ tuổi nhỏ không chịu nổi, để dùng sau tùy tình hình.","nguon":["@c0031"]},{"id":"hac-giao-moc","name":"Hắc Giao Mộc","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Kỳ mộc","soHuu":["Thạch Thôn"],"trangThai":"da-dung","blurb":"Kỳ mộc cứng nặng như sắt tinh, thân đen như Ly Long, là nguồn lửa tốt nhất để luyện khoáng chế binh khí.","detail":"Hắc Giao Mộc cứng nặng như sắt tinh, thân đen như Ly Long, đốt lên thế lửa hừng hực, là nguồn lửa tốt nhất để luyện khoáng, chế binh khí và nấu chân huyết. Thanh niên Thạch Thôn chặt nó làm nguồn lửa cho tẩy lễ.","nguon":["@c0031"]},{"id":"dao-ngoc-chuy-tu-kim","name":"Đao ngọc & chùy tử kim","cn":"","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Pháp khí","soHuu":["Thạch Vân Phong"],"trangThai":"dang-co","blurb":"Đao ngọc chi chít ký hiệu chém ánh sáng đào tim và chùy tử kim đập đầu độc trùng, dụng cụ tẩy lễ của tộc trưởng.","detail":"Tộc trưởng dùng đao ngọc chi chít ký hiệu tỏa ánh sáng để đào tim chí bảo Toan Nghê, và dùng chùy tử kim đập vỡ đầu độc trùng thành phụ dược trong quá trình tẩy lễ.","nguon":["@c0031"]},{"id":"co-duoc-doc-trung-phu-duoc","name":"Cổ dược & độc trùng phụ dược","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Phụ dược","soHuu":["Thạch Thôn"],"trangThai":"da-dung","blurb":"Cổ dược cùng các độc trùng (rết tím, Xuyên Sơn Giáp bạc, rắn vàng, nhện bạc biết bay) luyện thành phụ dược giảm đau và luyện hóa chân huyết.","detail":"Tộc trưởng ném cổ dược vào nước sôi rồi mở mấy chục bình ngọc thả độc trùng gồm rết tím dài hơn nửa mét, Xuyên Sơn Giáp bạc, rắn vàng nhỏ và nhện bạc biết bay, đập vỡ đầu chúng thành phụ dược giúp giảm đau và luyện hóa chân huyết Toan Nghê.","nguon":["@c0031"]},{"id":"dinh-den-dinh-duoc-co-khi-toc","name":"Đỉnh đen Cổ Khí tộc (dược đỉnh cổ)","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Dược đỉnh cổ","soHuu":["Thạch Vân Phong"],"trangThai":"dang-co","blurb":"Đỉnh to màu đen tổ tiên Cổ Khí tộc truyền lại, thực chất là một tòa dược đỉnh ghê gớm.","detail":"Đỉnh to màu đen khắc sơn hà nhật nguyệt chim muông ngư trùng và tiên dân thượng cổ. Khi luyện dược lộ chân tướng là dược đỉnh cổ: hình điêu khắc trở nên chân thực, phù văn trên vách đỉnh tự cháy sáng, truyền ra tiếng tế tự tụng kinh và hình tiên dân thượng cổ trấn áp Di chủng Thái cổ. Đỉnh luyện hóa Toan Nghê cùng ba loại chân huyết thành huyết thanh dùng tẩy lễ nhóc tỳ. Thạch Vân Phong nhận ra đỉnh có cùng biểu hiện giống đỉnh của các bộ tộc lớn.","nguon":["@c0032"]},{"id":"huyet-thanh-vang-kim","name":"Huyết thanh màu vàng kim","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Dược dịch","soHuu":[],"trangThai":"da-dung","blurb":"Dịch thuốc vàng kim luyện trong đỉnh đen dùng tẩy lễ nhóc tỳ, chứa mảnh thần tính Toan Nghê.","detail":"Dược dịch màu vàng kim do đỉnh đen luyện hóa Toan Nghê (và về sau thêm chân huyết Bò ma Ly Hỏa, Vượn Ác ma) tạo thành. Huyết thanh xông vào cơ thể nhóc tỳ qua lỗ chân lông, tẩy lễ từ ngoài vào trong khiến thân thể lột xác.","nguon":["@c0032"]},{"id":"dinh-hong-van","name":"Đỉnh Hống văn","cn":"","category":"khac","categoryLabel":"Trọng khí","phamCap":"","soHuu":["Nhóc tỳ"],"trangThai":"dang-co","blurb":"Đỉnh nặng tám ngàn cân nhóc tỳ nâng lên thử thần lực.","detail":"Chiếc đỉnh khắc văn Hống nặng tám ngàn cân; nhóc tỳ nâng lên đi vòng đất trống thử thần lực sau tẩy lễ, thả xuống khiến đất rung chuyển.","nguon":["@c0033","@c0032"]},{"id":"bao-cung-te-giac","name":"Bảo cung Tê giác","cn":"","category":"khac","categoryLabel":"Vũ khí","phamCap":"","soHuu":["Thạch Lâm Hổ"],"trangThai":"dang-co","blurb":"Cung lực căng lớn nhất trong tộc, quá thô to nhóc tỳ không kéo căng nổi.","detail":"Bảo cung làm từ sừng tê giác, lực căng lớn nhất trong Thạch thôn; Thạch Lâm Hổ đưa cho nhóc tỳ thử nhưng cánh tay nó quá ngắn nên không kéo căng được.","nguon":["@c0033"]},{"id":"khoi-xuong-tran-toan-nghe","name":"Khối xương trán Toan Nghê","cn":"","category":"nguyen-lieu","categoryLabel":"Bảo cụ / Nguyên liệu","phamCap":"","soHuu":["Nhóc tỳ"],"trangThai":"dang-co","blurb":"Xương trắng bằng lòng bàn tay chứa Phù văn nguyên thủy; hoạt tính mất dần nếu để lâu.","detail":"Khối xương trắng lấy giữa trán Toan Nghê, chứa Phù văn nguyên thủy. Nếu để lâu hoạt tính biến mất thì chỉ còn thành Bảo cụ chứ không luyện được Bảo thuật; tộc trưởng đưa cho nhóc tỳ ghi nhớ.","nguon":["@c0033"]},{"id":"dinh-co-thach-thon","name":"Đỉnh cổ Thạch Thôn","category":"khac","categoryLabel":"Khí vật luyện thể","soHuu":["Nhị Mãnh"],"trangThai":"dang-co","blurb":"Các đỉnh cổ xưa khắc điểu thú ngư trùng, nặng ngàn cân, dùng để trẻ Thạch Thôn luyện sức.","detail":"Những cái đỉnh cổ xưa của Thạch Thôn khắc điểu thú ngư trùng, mỗi cái nặng ngàn cân, nhiễm hung khí máu Toan Nghê. Trẻ trong thôn dùng chúng để luyện sức; Nhị Mãnh dễ dàng nâng một cái lên. Cường giả cảm nhận hung khí trên các đỉnh, biết có Thú Vương từng đổ máu chết tại đây.","nguon":["@c0035"]},{"id":"linh-hoa","name":"Linh hoa","cn":"","category":"dan-duoc","categoryLabel":"Linh vật","phamCap":"","soHuu":["Lôi Vân Khôn"],"trangThai":"da-dung","blurb":"Đóa linh hoa được Lôi Vân Khôn đổ vào nước sôi, tỏa hương ngào ngạt, linh khí tràn ra.","detail":"Linh hoa là linh vật Lôi Vân Khôn dùng pha vào nước sôi mời trẻ con Thạch thôn uống; khi thả vào nước liền tỏa hương ngào ngạt và linh khí tràn ra.","nguon":["@c0036"]},{"id":"tam-long-tuyet","name":"Tấm lông tuyết","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"","soHuu":["Ông lão Vân Thiên Cung"],"trangThai":"dang-co","blurb":"Tấm lông tuyết mà ông lão Vân Thiên Cung cầm trong tay khi đứng ra can Giao Bằng.","detail":"Vật phẩm ông lão Vân Thiên Cung nắm trong tay lúc hiện diện quanh Thạch thôn và can ngăn Giao Bằng động thủ.","nguon":["@c0036"]},{"id":"vong-xuong-ngon-cai-tu-son-con","name":"Vòng xương ngón cái","category":"phap-bao","categoryLabel":"Pháp bảo","soHuu":["Tử Sơn Côn"],"trangThai":"dang-co","blurb":"Vòng xương trên ngón cái Tử Sơn Côn, phát sáng phá giải lực đạo.","detail":"Đeo trên ngón cái Tử Sơn Côn, phát sáng phá giải lực đạo giúp tay không bị gãy khi bị Thạch Hạo đá văng.","nguon":["@c0038"]},{"id":"coi-xay-da","name":"Cối xay đá","category":"khac","categoryLabel":"Vật phẩm","soHuu":["Thạch Hạo"],"trangThai":"da-dung","blurb":"Cối xay đá mấy trăm cân Thạch Hạo dùng làm vũ khí.","detail":"Thạch Hạo dùng đá cối xay văng vào Lôi Minh Viễn, sau nắm cả cối xay mấy trăm cân đập thẳng vào đầu Giao Bằng khiến hắn phun máu bọt, rụng hai răng.","nguon":["@c0038"]},{"id":"bao-cot-toan-nghe-tranh-doat","name":"Bảo cốt Toan Nghê","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Bảo vật","soHuu":["Thạch Hạo"],"trangThai":"Bị nhiều thế lực tranh đoạt","blurb":"Xương của Toan Nghê, trục tranh đoạt của toàn chương; các cường giả đòi Thạch Thôn giao ra còn Thạch Hạo tuyên bố là của mình.","detail":"Bảo cốt Toan Nghê là xương của con Toan Nghê, trở thành mục tiêu tranh đoạt của toàn chương. La Phù Đại Trạch, bộ lạc Kim Lang, Lôi Tộc, Vân Thiên Cung cùng nhiều thế lực khác thi nhau chiêu mộ Thạch Hạo hoặc trực tiếp đòi Thạch Thôn giao ra, thực chất chỉ muốn đoạt lấy bảo cốt này cùng ba con dị cầm non. Giao Thương của La Phù Đại Trạch thờ ơ ra lệnh, mặc Giao Bằng đe dọa huyết tẩy Thạch Thôn. Thạch Hạo tuyên bố bảo cốt cùng Đại Bằng, Tiểu Thanh, Tử Vân đều là của mình.","nguon":["@c0039"]},{"id":"thai-co-ma-cam","name":"Thái Cổ Ma Cầm","cn":"","aliases":["Thái Cổ Hung Cầm"],"category":"khac","categoryLabel":"Khác","phamCap":"Thái Cổ","soHuu":["Thạch Hạo"],"trangThai":"Bảo Thuật do Thạch Hạo diễn hóa","blurb":"Bảo Thuật của Thạch Hạo, một con ma cầm che kín vòm trời nuốt chửng và nghiền nát ba dị cầm của ba thiên tài.","detail":"Thái Cổ Ma Cầm (còn gọi Thái Cổ Hung Cầm) là một trong những Bảo Thuật lợi hại của Thạch Hạo. Nó há to cái miệng kinh khủng một phát nuốt chửng con Lôi Cầm của Lôi Minh Viễn khiến con này tan rã. Khi che kín vòm trời, nó xé con Hôi Giao to bằng vại nước thành ba đoạn, nuốt Lôi Điểu và đánh nát Hỏa Lân, khiến ba thiên tài bị đánh bay, ho ra máu lăn lóc dính bụi.","nguon":["@c0039"]},{"id":"phi-giao-giao-bang","name":"Phi Giao","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"Dị thú","soHuu":["Giao Bằng"],"trangThai":"Bị cành liễu non đâm chết","blurb":"Con giao dài hai mươi mấy mét Giao Bằng cưỡi, sát khí lan tỏa, nhào xuống định huyết tẩy Thạch Thôn thì bị cành liễu non đâm thủng.","detail":"Phi Giao là con giao dài hai mươi mấy mét, sát khí lan tỏa, do Giao Bằng cưỡi. Giao Bằng lệnh nó xông xuống huyết tẩy Thạch Thôn. Khi con Phi Giao đang há mồm xông tới, một đạo ánh sáng óng ánh xông lên — cành liễu non xanh biếc phát hào quang chọc thủng trời cao. Con Phi Giao mở to mắt, khiếp sợ tới cùng cực, gào thét một tiếng rồi bị cành liễu xanh biếc đâm thủng cơ thể khiến nó im bặt.","nguon":["@c0039"]},{"id":"ba-chim-non-dai-bang-tieu-thanh-tu-van","name":"Ba con chim non (Đại Bằng · Tiểu Thanh · Tử Vân)","cn":"","aliases":["Đại Bằng","Tiểu Thanh","Tử Vân"],"category":"khac","categoryLabel":"Khác","phamCap":"Dị cầm","soHuu":["Thạch Hạo"],"trangThai":"Bị nhiều thế lực thèm muốn","blurb":"Ba con chim non Thạch Hạo coi là bạn, hậu duệ Thái Cổ Ma Cầm, được nhiều thế lực đòi giao ra.","detail":"Đại Bằng, Tiểu Thanh và Tử Vân là ba con chim non mà Thạch Hạo coi là bạn, biểu hiện thân mật. Chúng là hậu duệ Thái Cổ Ma Cầm, tiềm năng lớn nên bị các cường giả thèm muốn đòi giao ra cùng bảo cốt Toan Nghê. Thạch Hạo kiên quyết tuyên bố ba con là của mình.","nguon":["@c0039"]},{"id":"canh-lieu-non-than-vat","name":"Cành liễu non","cn":"","aliases":["Xích thần trật tự"],"category":"than-khi","categoryLabel":"Thần khí","phamCap":"Thần vật","soHuu":["Liễu Thần (cây liễu Thạch Thôn)"],"trangThai":"Xuất hiện cứu Thạch Thôn","blurb":"Cành liễu non xanh biếc như điêu khắc bằng thần ngọc, phát hào quang xán lạn chọc thủng trời cao, đâm thủng cơ thể con Phi Giao.","detail":"Cành liễu non xanh biếc như điêu khắc bằng thần ngọc, phát ra hào quang xán lạn chọc thủng trời cao. Khi con Phi Giao đang xông tới định huyết tẩy Thạch Thôn, cành liễu đột nhiên xông lên khiến Phi Giao khiếp sợ tới cùng cực gào thét. Ngay sau đó cành liễu xanh biếc — ví như xích thần trật tự, rừng rực ánh sáng xanh — đâm thủng cơ thể con Phi Giao khiến nó im bặt. Vật được ví giống “xích thần trật tự”, ám chỉ uy năng và lai lịch phi thường.","nguon":["@c0039"]},{"id":"chat-dich-tinh-luyen-phi-giao","name":"Chất dịch tinh luyện từ Phi Giao","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","soHuu":[],"trangThai":"dang-co","blurb":"Giọt chất lỏng màu xám tỏa sức sống trên cành liễu, do cây liễu hấp thu tinh luyện từ thân Phi Giao.","detail":"Sau khi Liễu Thần giết Phi Giao và hút tinh khí, thân nó phân hủy rơi thành mấy khối; chất dịch tinh luyện được cây liễu hấp thu, đọng thành giọt màu xám tỏa sức sống trên cành liễu.","nguon":["@c0040"]},{"id":"xuong-quy-toan-nghe-chi-bao","name":"Xương quý Toan Nghê (phù văn chí bảo)","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"Chí bảo","soHuu":[],"trangThai":"dang-co","blurb":"Chí bảo xương quý Toan Nghê kèm phù văn Toan Nghê mà đám Kim Lang cho là có ở Thạch thôn.","detail":"Ba Đồ báo tin rằng trong thôn cổ có xương quý Toan Nghê chí bảo cùng hậu duệ ma cầm Thái cổ, kèm phù văn Toan Nghê. Tin này khiến các đại tộc và Chí cường giả trong phạm vi hai mươi lăm ngàn cây số chấn động kéo về tranh đoạt.","nguon":["@c0041"]},{"id":"son-bao-dai-hoang","name":"Sơn bảo (Đại Hoang)","category":"khac","categoryLabel":"Bảo vật","phamCap":"","soHuu":[],"trangThai":"","blurb":"Bảo vật ẩn trong dãy núi hai năm chưa bị tìm ra, đồn là thánh dược tự bay hoặc thứ còn sống.","detail":"Bảo vật ẩn hai năm trong dãy núi Thương Mãng thuộc vùng Đại Hoang, được đồn đoán là thánh dược có thể tự bay hoặc là thứ còn sống. Chí cường bí ẩn cho Di Chủng Thái Cổ lùa bầy thú dọn bãi để bảo vật này sắp xuất thế.","nguon":["@c0042"]},{"id":"bao-cu-da-soi-kim-lang","name":"Bảo Cụ da sói (Kim Lang)","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Cực hiếm","soHuu":["Tộc trưởng bộ lạc Kim Lang"],"trangThai":"dang-co","blurb":"Lớp da cũ con Tế Linh Kim Lang lột ra, tế luyện thành Bảo Cụ hoàn chỉnh, hào quang vàng, sinh động như Thần Lang sống.","detail":"Sau khi con Tế Linh Kim Lang lột da hóa chân thân, lớp da vàng cũ được tế luyện thành một Bảo Cụ da sói hoàn chỉnh, tỏa hào quang vàng, sinh động như con Thần Lang sống, cực hiếm và mạnh mẽ, xông tấn công gốc rễ cây liễu cháy đen của Thạch Thôn.","nguon":["@c0043"]},{"id":"bao-cu-soi-than-kim-lang","name":"Bảo cụ da sói vàng kim (Sói thần)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Bộ lạc Kim Lang"],"trangThai":"hong","blurb":"Bảo cụ lột từ đệ nhất Tế linh, toàn thân như đúc hoàng kim.","detail":"Lột từ đệ nhất Tế linh trong bán kính hai mươi lăm nghìn cây số, toàn thân như đúc hoàng kim, vung vuốt phá rễ cây liễu; bị rễ cây vọt lên như Cầu Long cuộn kéo vào lòng đất, cắt gãy móng vuốt thành ba đoạn, da sói khô mục hóa phân bón.","nguon":["@c0044"]},{"id":"lang-nha-chuy","name":"Lang Nha Chủy","category":"phap-bao","categoryLabel":"Bảo Cụ / Tổ Khí","phamCap":"Tổ Khí","soHuu":["Tộc trưởng bộ lạc Kim Lang","Thần Lang"],"trangThai":"bi-cuop","blurb":"Tổ Khí của bộ lạc Kim Lang, dao găm vàng hình răng thú, chính là răng của một Tế Linh mạnh của cổ quốc.","detail":"Dao găm dài một thước toàn thân màu vàng, hình như răng thú mài thành, là răng của một Tế Linh mạnh của cổ quốc; thần tính đã bị cổ quốc lấy đi. Là Tổ Khí bộ lạc Kim Lang do tổ tiên lập công được cổ quốc ban thưởng. Khi tộc trưởng Kim Lang dùng nó chống cây liễu thì thất bại; sau đó Thần Lang xông tới cắn lấy Lang Nha Chủy rồi bỏ chạy mất, bị tộc lão coi là điềm bất tường.","nguon":["@c0045"]},{"id":"bao-cu-da-soi-vang-kim-lang","name":"Bảo Cụ da sói vàng (Kim Lang)","category":"phap-bao","categoryLabel":"Bảo Cụ","phamCap":"Bảo Cụ","soHuu":["Bộ lạc Kim Lang"],"trangThai":"hong","blurb":"Tấm da màu vàng ra oai tấn công Thần Lang, bị cây liễu hủy.","detail":"Bảo Cụ da sói màu vàng của bộ lạc Kim Lang, được điều động ra oai tấn công Thần Lang trong lúc hỗn chiến, sau bị cây liễu hủy diệt.","nguon":["@c0045"]},{"id":"bao-cu-the-than-tu-son-hau","name":"Bảo Cụ thế thân của Tử Sơn Hầu","category":"phap-bao","categoryLabel":"Bảo Cụ","phamCap":"Bảo Cụ","soHuu":["Tử Sơn Hầu"],"trangThai":"hong","blurb":"Bảo Cụ ngưng tụ thành hình người chịu chết thay cho Tử Sơn Hầu.","detail":"Ngưng tụ thành hình người khổng lồ màu tím chịu chết thay giúp Tử Sơn Hầu trốn thoát; bị cành liễu đâm xuyên lấy tinh hoa thần tính, còn Tử Sơn Hầu thì thoát nạn.","nguon":["@c0045"]},{"id":"con-sat-khong-lo","name":"Côn sắt khổng lồ","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Sinh vật dùng côn sắt"],"trangThai":"dang-co","blurb":"Thanh côn sắt to như cột chống trời của đối thủ sinh vật mắt xanh, được ký hiệu nguyên thủy gia trì tăng thần uy.","detail":"Trong đại chiến bốn sinh vật cực mạnh sâu trong Thương Mãng Sơn Mạch, sinh vật khổng lồ dùng thanh côn sắt to như cột chống trời đánh trả sinh vật mắt xanh; thanh côn được ký hiệu nguyên thủy gia trì khiến thần uy tăng mạnh.","nguon":["@c0046"]},{"id":"hon-don-chi-bao-thanh-vat","name":"Hỗn độn chí bảo","cn":"","aliases":["Thánh vật (chưa rõ danh)"],"category":"khac","categoryLabel":"Bảo vật trục","phamCap":"Truyền thuyết","soHuu":[],"trangThai":"dang-co","blurb":"Báu vật xuất thế ở trung tâm Thương Mãng Sơn Mạch, tiên quang xông trời, là mục tiêu tranh đoạt của bốn sinh vật cực mạnh.","detail":"Ở trung tâm Thương Mãng Sơn Mạch, loạn thạch vỡ nát, tiên quang xông trời — hỗn độn chí bảo xuất thế. Bốn sinh vật cực mạnh quyết đấu sinh tử để tranh đoạt báu vật vừa đào được. Danh tính thật chưa rõ.","nguon":["@c0046"]},{"id":"thanh-vat-trang-non-ong-anh","name":"Thánh vật (trắng nõn óng ánh)","cn":"","category":"khac","categoryLabel":"Bảo vật","phamCap":"Thánh vật","soHuu":[],"trangThai":"Bị tứ đại sinh linh Chí tôn tranh đoạt; đổi chủ nhiều lần, sau bị hung cầm mắt trăng máu bắt được","blurb":"Bảo vật trắng nõn óng ánh mà tứ đại sinh linh Chí tôn quyết chiến tranh đoạt tại dãy núi Thương Mãng.","detail":"Thánh vật hình dạng trắng nõn óng ánh, là tâm điểm cuộc quyết chiến của bốn sinh linh Chí tôn tại dãy núi Thương Mãng. Trong trận đại chiến, thánh vật đổi chủ nhiều lần nhưng không con nào thật sự lấy được, khiến chiến trường lan rộng ngàn dặm và hủy diệt cả dãy núi Thương Mãng thành núi cụt. Cuối cùng một con hung cầm khổng lồ mắt trăng máu (Thôn Thiên Tước) bắt được rồi bay ra xa.","nguon":["@c0048"]},{"id":"bao-xuong-nguyen-thuy-di-chung-thai-co","name":"Bảo xương Nguyên thủy Di chủng Thái cổ","cn":"","category":"khac","categoryLabel":"Trấn vật","phamCap":"Bảo xương Nguyên thủy Thái cổ","soHuu":[],"trangThai":"Không đủ ngăn tứ đại sinh linh, vùng núi loạn thạch phá trời","blurb":"Mười mấy khối bảo xương nguyên thủy Di chủng Thái cổ vốn trấn giữ vùng núi Thương Mãng.","detail":"Gồm mười mấy khối Bảo xương của Di chủng Thái cổ nguyên thủy, vốn dùng để bảo vệ và trấn giữ vùng núi Thương Mãng. Khi tứ đại sinh linh Chí tôn quyết chiến tranh đoạt Thánh vật, các khối bảo xương này không đủ sức bảo vệ nổi vùng núi, khiến nơi đây loạn thạch phá trời và cuối cùng cả dãy núi bị hủy diệt thành núi cụt.","nguon":["@c0048"]},{"id":"con-sat-sinh-linh-chi-ton","name":"Côn sắt (của sinh linh cầm côn)","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chí tôn sinh linh","soHuu":[],"trangThai":"dang-co","blurb":"Binh khí khổng lồ của sinh linh chí tôn cầm côn, quét sụp cả vòm trời khi đối đầu Thôn Thiên Tước.","detail":"Một thanh côn sắt khổng lồ do sinh linh chí tôn ẩn trong sương mù cầm giữ, một cú quét có thể sụp cả vòm trời, dùng đối đầu với Thôn Thiên Tước trong trận đại chiến tứ chí tôn.","nguon":["@c0049"]},{"id":"long-tu-ngu","name":"Long Tu Ngư","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Cực phẩm","soHuu":[],"trangThai":"dang-co","blurb":"Cá lớn vảy vàng phẩm chất cực tốt, hai râu rồng óng ánh, giàu linh tính, ăn thường xuyên cường gân tráng cốt.","detail":"Loài cá lớn sống ở con sông vùng đất mới, vảy vàng phẩm chất cực tốt, bên miệng mọc hai râu rồng óng ánh phát mùi thơm, nặng mười mấy cân, giàu linh tính. Thạch Vân Phong nhận ra ăn thường xuyên có thể cường gân tráng cốt tăng sức mạnh, dặn không được bắt giết tùy tiện để chúng sinh sống quanh năm.","nguon":["@c0050"]},{"id":"ngu-sac-ke","name":"Ngũ Sắc Kê","aliases":["Tiểu Loan Điểu"],"category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Chim lông rực rỡ dài hơn hai mét sinh trưởng giống Loan Điểu, là thuốc bổ cốt liền xương thần kỳ.","detail":"Đàn chim lông rực rỡ dài hơn hai mét ở hồ xanh biếc vùng đất mới, sinh trưởng giống Loan Điểu, còn gọi Tiểu Loan Điểu. Là thuốc bổ cốt — đun cả thịt lẫn xương ăn giúp liền xương thần kỳ. Thạch Vân Phong dặn không được bắt giết tùy tiện.","nguon":["@c0050","@c0051"]},{"id":"long-do-tin-vat-tuoc-do","name":"Lông đỏ (tín vật tước đỏ)","category":"khac","categoryLabel":"Tín vật","phamCap":"Vật thường (thần tính đã bị thu lại)","soHuu":["Thạch Thôn"],"trangThai":"dang-co","blurb":"Chiếc lông đỏ rực tước đỏ rơi lại làm tín vật cho Thạch Thôn.","detail":"Trước khi bay đi, tước đỏ để lại một cọng lông đỏ rực đẹp mắt làm tín vật cho thôn nhân, dặn nếu có người tìm phiền toái thì cứ lấy ra; nhưng nó đã hít thu lại thần tính từ chiếc lông, chỉ còn là lông thường.","nguon":["@c0051"]},{"id":"giot-nuoc-tien-chau-lieu-than","name":"Giọt nước Tiên Châu của Liễu Thần","category":"khac","categoryLabel":"Linh vật","phamCap":"Không rõ","soHuu":["Liễu Thần"],"trangThai":"da-dung","blurb":"Giọt nước trong suốt như Tiên Châu do cành liễu tiết ra, trị lành mọi vết thương.","detail":"Cây liễu cháy đen phát hào quang xanh, cành liễu tiết ra giọt nước trong suốt như Tiên Châu có hào quang và hương thơm; chữa lành vết thương xuyên bụng ngực và các lỗ trên đầu tước đỏ, khử hết ký hiệu phá hủy sinh cơ.","nguon":["@c0051"]},{"id":"long-can-xa","name":"Long Cân Xà","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Bảo dược hiếm thấy","soHuu":["Thạch thôn"],"trangThai":"Bảo dược của Thạch thôn phát hiện tại nơi định cư mới","blurb":"Rắn gân rồng cực hung, gân hầm nhừ ăn vào cường tráng gân cốt, bảo dược hiếm thấy.","detail":"Long Cân Xà (rắn gân rồng) là loài rắn cực hung được thôn nhân Thạch thôn phát hiện một năm sau khi định cư tại vùng đất mới. Gân của nó đem hầm nhừ, ăn vào có công hiệu cường tráng gân cốt, được xem là một loại bảo dược hiếm thấy, quý giá cho việc rèn luyện thân thể.","nguon":["@c0052"]},{"id":"trung-xich-vu-hac-tieu-loan-dieu","name":"Trứng Xích Vũ Hạc / Tiểu Loan Điểu","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Bảo dược","soHuu":[],"trangThai":"da-dung","blurb":"Trứng chim dị cầm ở hồ Thạch thôn, nướng lên là bảo dược bổ dưỡng, ăn vào đỏ ran cả người.","detail":"Trứng của Xích Vũ Hạc (dài mấy mét, đỏ như lửa) và Tiểu Loan Điểu ở hồ xanh ngọc bích Thạch thôn. Mao Cầu trộm hai mươi mấy quả, đám nhóc nướng ăn — là bảo dược bổ dưỡng, ăn vào đỏ ran cả người.","nguon":["@c0054"]},{"id":"co-kim-ti-lot-to","name":"Cỏ Kim Ti","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"","soHuu":[],"trangThai":"","blurb":"Loại cỏ mềm mại lót trong tổ hung cầm Thanh Lân Ưng.","detail":"Cỏ Kim Ti là loại cỏ mềm mại được Thanh Lân Ưng dùng lót trong tổ; giữa lớp cỏ mềm ẩn giấu các tấm vảy kim loại sắc bén khiến Thạch Đại Tráng dẫm phải tóe máu chân.","nguon":["@c0008"]},{"id":"tui-da-thu-cat-trung","name":"Túi da thú","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"","soHuu":["Thạch Đại Tráng","Nhị Mãnh","Bì Hầu"],"trangThai":"dang-co","blurb":"Túi da thú lũ trẻ mang theo để cất ba quả trứng Thanh Lân Ưng.","detail":"Túi da thú là vật dụng lũ trẻ Thạch Thôn mang theo khi vào rừng; ba đứa lớn mỗi đứa vác một quả trứng Thanh Lân Ưng cất vào túi trước khi leo xuống vách đá rời đi.","nguon":["@c0008"]},{"id":"dinh-den-bao-dinh-che-thuoc-thach-thon","name":"Đỉnh đen bảo đỉnh chế thuốc (Cổ khí tộc)","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Thạch Vân Phong"],"trangThai":"dang-co","blurb":"Đỉnh đen thường ngày của Thạch Thôn, khi luyện lộ ra là bảo đỉnh chế thuốc thần dị.","detail":"Đỉnh đen khắc sơn hà nhật nguyệt chim muông. Khi luyện tẩy lễ, hoa văn sống dậy chân thực, phù văn tự cháy, hiện lên tiên dân thượng cổ và âm thanh tế tự tụng kinh; tiên dân và tiếng tụng kinh trên vách đỉnh trấn áp các Di chủng Thái cổ bị nhốt bên trong. Thạch Vân Phong nhận ra đỉnh có biểu hiện giống đỉnh của các bộ tộc lớn, gợi mở nguồn gốc phi thường của Cổ khí tộc.","nguon":["@c0032"]},{"id":"manh-than-tinh-toan-nghe","name":"Mảnh vỡ thần tính Toan Nghê","category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":["Thạch Hạo"],"trangThai":"da-dung","blurb":"Mảnh thần tính do tổ hoàng Thái cổ Toan Nghê truyền thừa, đã chết không có ý thức thật.","detail":"Màu vàng kim dài hơn một thước, giãy dụa xông ra rít gào khi đỉnh chấn động. Là mảnh vỡ thần tính từ tổ hoàng Thái cổ Toan Nghê, đã chết không có ý thức thật. Bị các điểm sáng quanh nhóc tỳ tịnh hóa, tan rã thành chùm sáng thần tính dung vào huyết thanh để tẩm bổ thân nhóc tỳ.","nguon":["@c0032"]},{"id":"dinh-hong-van-tam-ngan-can","name":"Đỉnh Hống văn tám nghìn cân","category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":["Thạch Thôn"],"trangThai":"dang-co","blurb":"Đỉnh nặng nhất trong tộc, khắc một con Hống hung dữ, dùng thử thần lực.","detail":"Đỉnh nặng tám nghìn cân khắc một con Hống hung dữ, là đỉnh nặng nhất trong tộc. Sau lột xác, nhóc tỳ nâng lần lượt đỉnh đồng nghìn cân, đỉnh hắc kim năm ngàn cân rồi cuối cùng nâng đỉnh Hống văn tám nghìn cân qua đỉnh đầu để thử thần lực.","nguon":["@c0032"]},{"id":"vong-xuong-phat-sang-tu-son-con","name":"Vòng xương phát sáng","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Tử Sơn Côn"],"trangThai":"dang-co","blurb":"Vòng xương đeo trên ngón cái Tử Sơn Côn, phát sáng phá giải lực đạo giúp tay không gãy khi đón chưởng Thạch Hạo.","detail":"Khi đón chưởng của Thạch Hạo, tay Tử Sơn Côn đau như rạn xương, nhờ vòng xương trên ngón cái phát sáng phá giải lực đạo mới không bị gãy.","nguon":["@c0038"]},{"id":"long-tuyet-van-thien-cung","name":"Lông tuyết","category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":["Ông lão Vân Thiên Cung"],"trangThai":"dang-co","blurb":"Một cái lông tuyết do ông lão Vân Thiên Cung cầm trong tay.","detail":"Vật phẩm ông lão đến từ Vân Thiên Cung mang theo khi được mời làm trọng tài trận đấu.","nguon":["@c0038"]},{"id":"to-khi-thach-thon","name":"Hai món tổ khí của Thạch Thôn","category":"than-khi","categoryLabel":"Thần khí","phamCap":"Không rõ","soHuu":["Thạch Thôn"],"trangThai":"dang-co","blurb":"Hai món tổ khí của Thạch Thôn, vật rơi ra từ thân chủng tộc Thái Cổ siêu cấp.","detail":"Hai món tổ khí của Thạch Thôn là vật rơi ra từ thân hai con thuộc chủng tộc Thái Cổ siêu cấp, sau khi được mài giũa tế luyện trở thành vật báu đáng sợ của bộ tộc.","nguon":["@c0012","@c0011"]},{"id":"dinh-den-duoc-dinh-co","name":"Đỉnh đen (dược đỉnh cổ Thạch thôn)","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Dược đỉnh cổ","soHuu":["Thạch thôn"],"trangThai":"dang-co","blurb":"Đỉnh đen tổ tiên Thạch thôn truyền lại, lộ ra là bảo đỉnh chế thuốc cổ ghê gớm khi luyện dược.","detail":"Đỉnh đen tổ tiên Thạch thôn truyền lại, thường ngày không đáng chú ý. Khi luyện thuốc lộ ra là bảo đỉnh chế thuốc cổ: vách khắc sơn hà nhật nguyệt, chim muông ngư trùng chân thực như sắp sống lại, phù văn tự cháy, tiên dân thượng cổ hiện lên, phát khí tức cổ xưa cùng âm thanh tế tự và tiếng tụng kinh vang vọng.","nguon":["@c0032"]},{"id":"sung-bo-ma-ly-hoa","name":"Sừng quý Bò ma Ly Hỏa","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Chân huyết Thái cổ","soHuu":["Thạch thôn"],"trangThai":"da-dung","blurb":"Sừng đỏ thẫm sáng chói chứa chân huyết Di chủng Thái cổ, đổ vào đỉnh đợt tẩy lễ hai.","detail":"Sừng quý màu đỏ thẫm sáng chói của Bò ma Ly Hỏa, chứa chân huyết Thái cổ; Thạch Lâm Hổ trích máu đổ vào đỉnh trong đợt tẩy lễ thứ hai của nhóc tỳ.","nguon":["@c0032"]},{"id":"canh-tay-vuon-ac-ma","name":"Cánh tay Vượn Ác ma","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Chân huyết Thái cổ","soHuu":["Thạch thôn"],"trangThai":"da-dung","blurb":"Cánh tay Vượn Ác ma chứa chất lỏng màu đen, đổ vào đỉnh đợt tẩy lễ hai.","detail":"Cánh tay của Vượn Ác ma chứa chất lỏng màu đen (chân huyết Di chủng Thái cổ); Thạch Lâm Hổ trích đổ vào đỉnh trong đợt tẩy lễ thứ hai của nhóc tỳ.","nguon":["@c0032","@c0025"]},{"id":"dinh-dong-nghin-can","name":"Đỉnh đồng nghìn cân","category":"khac","categoryLabel":"Khác","phamCap":"Nghìn cân","soHuu":["Nhóc tỳ"],"trangThai":"dang-co","blurb":"Đỉnh đồng nặng nghìn cân nhóc tỳ từng nâng được.","detail":"Đỉnh đồng nặng nghìn cân, một trong những vật nhóc tỳ từng nâng được thể hiện thần lực.","nguon":["@c0032"]},{"id":"dinh-hac-kim-nam-ngan-can","name":"Đỉnh hắc kim năm ngàn cân","category":"khac","categoryLabel":"Khác","phamCap":"Năm ngàn cân","soHuu":["Thạch thôn"],"trangThai":"dang-co","blurb":"Đỉnh hắc kim nặng năm ngàn cân nhóc tỳ nâng lên trong màn thử thần lực.","detail":"Đỉnh hắc kim nặng năm ngàn cân, nhóc tỳ nâng lên trong màn thử thần lực sau khi lột xác.","nguon":["@c0032"]},{"id":"dinh-den-che-thuoc","name":"Đỉnh đen (bảo đỉnh chế thuốc Cổ khí tộc)","aliases":["Đỉnh đen","Dược đỉnh Cổ khí tộc"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Bảo đỉnh chế thuốc thần dị","soHuu":["Thạch Vân Phong"],"trangThai":"dang-co","blurb":"Đỉnh dày nặng vốn dùng thường ngày của Cổ khí tộc, hóa ra là một bảo đỉnh chế thuốc thần dị tổ truyền.","detail":"Đỉnh to màu đen khắc sơn hà nhật nguyệt chim muông ngư trùng trên vách. Khi luyện thuốc, hoa văn trở nên chân thực, phù văn tự cháy, hiện tiên dân thượng cổ cùng âm thanh tế tự tụng kinh, trấn áp các Di chủng Thái cổ. Dùng làm nơi tẩy lễ cho nhóc tỳ, chứa huyết thanh Toan Nghê cùng chân huyết Bò ma Ly Hỏa và Vượn Ác ma. Tộc trưởng Thạch Vân Phong kinh dị nhận ra đây là một tòa dược đỉnh ghê gớm do tổ tiên truyền lại.","nguon":["@c0032"]},{"id":"dinh-hong-van-tam-nghin-can","name":"Đỉnh Hống văn tám nghìn cân","aliases":["Đỉnh Hống văn"],"category":"khac","categoryLabel":"Khác","phamCap":"Đỉnh nặng nhất trong tộc","soHuu":["Thạch thôn"],"trangThai":"dang-co","blurb":"Đỉnh nặng nhất trong tộc, khắc một con Hống hung dữ, dùng thử thần lực nhóc tỳ.","detail":"Đỉnh nặng tám nghìn cân, khắc hình một con Hống hung dữ, là đỉnh nặng nhất trong Thạch thôn. Sau khi lột xác, nhóc tỳ lần lượt nâng đỉnh đồng nghìn cân, đỉnh hắc kim năm ngàn cân, cuối cùng nâng được đỉnh Hống văn tám nghìn cân qua đỉnh đầu, chứng tỏ thần lực phi thường.","nguon":["@c0032"]},{"id":"dinh-hac-kim","name":"Đỉnh hắc kim (năm ngàn cân)","category":"khac","categoryLabel":"Khác","phamCap":"Đỉnh thử sức nặng năm ngàn cân","soHuu":["Thạch thôn"],"trangThai":"dang-co","blurb":"Một trong các đỉnh dùng thử sức nhóc tỳ sau lột xác.","detail":"Đỉnh hắc kim nặng năm ngàn cân, được nhóc tỳ nâng lên trong lúc thử thần lực trước khi nâng đỉnh Hống văn tám nghìn cân.","nguon":["@c0032"]},{"id":"huyet-thanh-vang-kim-toan-nghe","name":"Huyết thanh vàng kim (dược dịch Toan Nghê)","category":"khac","categoryLabel":"Dược dịch","phamCap":"Chưa rõ","soHuu":[],"trangThai":"da-dung","blurb":"Chất lỏng vàng kim đặc sôi trong đỉnh đen, sinh ra dược hồn Toan Nghê.","detail":"Huyết thanh vàng kim đặc sôi trào trong đỉnh đen dùng cho tẩy lễ; sinh ra một con Toan Nghê vàng kim — mảnh vỡ thần tính truyền thừa từ tổ hoàng Thái cổ Toan Nghê — dài hơn một thước. Trong tẩy lễ, chất lỏng này xông vào cơ thể nhóc tỳ qua lỗ chân lông, tẩm bổ xương thịt cho tới khi gần cạn thì lột xác lần một hoàn tất.","nguon":["@c0032"]},{"id":"dinh-den-gia-truyen","name":"Đỉnh đen gia truyền","aliases":["Dược đỉnh","Bảo đỉnh chế thuốc"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Thạch thôn","Thạch Vân Phong"],"trangThai":"dang-co","blurb":"Đỉnh đen dày nặng gia truyền của Cổ khí tộc, hóa ra là một dược đỉnh ghê gớm.","detail":"Đỉnh đen dày nặng của Cổ khí tộc, khắc sơn hà nhật nguyệt chim muông ngư trùng. Khi luyện dược, phù văn tự cháy, hoa văn sống động như sắp sống lại, có tiếng tế tự và tụng kinh của tiên dân thượng cổ vang lên. Thạch Vân Phong kinh dị nhận ra nó vốn là một dược đỉnh ghê gớm giống đỉnh của các bộ tộc lớn, dùng để chủ trì tẩy lễ cho nhóc tỳ.","nguon":["@c0032"]},{"id":"dinh-den-bao-dinh-che-thuoc","name":"Đỉnh đen (bảo đỉnh chế thuốc)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Bảo đỉnh chế thuốc","soHuu":["Thạch Vân Phong"],"trangThai":"dang-co","blurb":"Đỉnh đen tổ tiên Cổ khí tộc truyền lại, thường ngày không đáng chú ý nhưng thực chất là một tòa dược đỉnh chế thuốc ghê gớm.","detail":"Đỉnh to màu đen do tổ tiên Thạch thôn truyền lại. Trong quá trình tẩy lễ cho nhóc tỳ, đỉnh tỏa bảo quang, vách khắc sơn hà nhật nguyệt chim muông sống động, phù văn tự cháy, hiện lên hình tiên dân thượng cổ tụng kinh và cộng minh với nhóc tỳ. Thạch Vân Phong kinh dị nhận ra đây thật sự là một bảo đỉnh chế thuốc.","nguon":["@c0032"]},{"id":"hac-dinh","name":"Hắc đỉnh","cn":"","aliases":["Đỉnh to màu đen","Dược đỉnh Cổ khí tộc"],"category":"phap-bao","categoryLabel":"Dược đỉnh","phamCap":"Dược đỉnh cổ","soHuu":[],"trangThai":"dang-co","blurb":"Đỉnh đen dày nặng tổ tiên Cổ khí tộc truyền lại, thường ngày không đáng chú ý nhưng thật ra là một tòa dược đỉnh cổ ghê gớm.","detail":"Cái đỉnh đen thường ngày chẳng ai để ý, dùng để tẩy lễ cho nhóc tỳ. Khi luyện thuốc, hoa văn sơn hà nhật nguyệt chim muông ngư trùng trên đỉnh trở nên chân thực như sắp sống lại, tỏa khí tức cổ xưa; phù văn trên vách đỉnh tự cháy sáng, vang tiếng hung cầm mãnh thú lẫn tiếng tế tự tụng kinh, hiện lên tiên dân thượng cổ, mặt đỉnh dần trong suốt luyện hóa huyết thanh. Thạch Vân Phong kinh dị nhận ra đây là một tòa dược đỉnh cổ ghê gớm, có cùng biểu hiện với đỉnh của các bộ tộc lớn.","nguon":["@c0032"]},{"id":"duoc-hon-toan-nghe","name":"Dược hồn Toan Nghê","cn":"","aliases":["Mảnh vỡ thần tính Toan Nghê"],"category":"dan-duoc","categoryLabel":"Dược hồn","phamCap":"Truyền thừa Thái cổ","soHuu":["Nhóc tỳ"],"trangThai":"da-dung","blurb":"Con Toan Nghê vàng kim dài hơn một thước — mảnh vỡ thần tính truyền thừa từ tổ hoàng Thái cổ Toan Nghê, tinh hoa dược tính trong hắc đỉnh.","detail":"Dược hồn hình con Toan Nghê màu vàng kim, không có ý thức thật, tự thiêu đốt và va chạm điên cuồng vào nắp đỉnh muốn xông ra. Trong quá trình tẩy lễ, nhóc tỳ dùng thần tính và vô số điểm sáng như thần linh tụng kinh dẫn dắt, tịnh hóa và dung luyện nó; con Toan Nghê giãy dụa né tránh rồi tan rã, bị hắc đỉnh luyện hóa thành các chùm sáng thần tính vàng kim dung nhập huyết dịch nhóc tỳ.","nguon":["@c0032"]},{"id":"dinh-dong-thach-thon","name":"Đỉnh đồng xanh nghìn cân","category":"khac","categoryLabel":"Vật phẩm","soHuu":[],"trangThai":"dang-co","blurb":"Đỉnh đồng xanh nặng ngàn cân dùng làm vật thử sức của bọn trẻ Thạch Thôn.","detail":"Vật thử sức đặt ở Thạch Thôn; Thạch Hạo, Thạch Đại Tráng và Thạch Mãnh từng nâng hoặc gần nâng được đỉnh đồng này. Việc nâng được đỉnh đưa Thạch Hạo trở thành phần tử nòng cốt trong đám trẻ.","nguon":["@c0007"]},{"id":"cung-lon-sung-rong","name":"Cung lớn sừng rồng","category":"phap-bao","categoryLabel":"Vũ khí","phamCap":"Không rõ","soHuu":["Thạch Lâm Hổ","Bái Phong"],"trangThai":"dang-co","blurb":"Cung lớn màu đen cao quá nửa thân người làm từ sừng rồng, dùng đấu tiễn.","detail":"Cây cung lớn màu đen làm từ sừng rồng, cao quá nửa thân người. Cả Thạch Lâm Hổ và Bái Phong đều dùng loại cung này để đấu tiễn — hai bên bắn liên tiếp mười mấy mũi tên va chạm nhau giữa không trung, không phân cao thấp. (@c0014)","nguon":["@c0014"]},{"id":"cung-lon-ten-sat-bai-phong","name":"Cung lớn và tên sắt của Bái Phong","category":"phap-bao","categoryLabel":"Pháp bảo","soHuu":["Bái Phong"],"trangThai":"dang-co","blurb":"Cung lớn cao hơn nửa người kèm tên sắt to dài của Bái Phong.","detail":"Cung lớn cao hơn nửa người, tên sắt to dài bắn nứt kim loại, đủ bắn chết Long Giác Tượng. Bái Phong dùng bắn liên tiếp tám mũi tên sắt nhắm chỗ yếu hại Thạch Hạo nhưng bị né năm mũi và đánh bay ba mũi cắm sâu vào đá.","nguon":["@c0015"]},{"id":"truong-mau-huyet-van-thiet","name":"Trường mâu Huyết Văn Thiết","category":"phap-bao","categoryLabel":"Pháp bảo","soHuu":["Bái Phong"],"trangThai":"hong","blurb":"Trường mâu màu đỏ đậm làm bằng Huyết Văn Thiết của Bái Phong.","detail":"Trường mâu màu đỏ đậm chế từ Huyết Văn Thiết, được Bái Phong dùng đâm ngực Thạch Hạo. Bị Thạch Hạo vung tay phải tạo quỹ tích phát sáng chém đứt thành hai đoạn mà tay trắng nõn không bị tổn thương; mâu gãy sau đó bị Bái Phong ném nhắm mắt phải Thạch Hạo.","nguon":["@c0015"]},{"id":"bao-cu-rang-thu","name":"Bảo cụ răng thú (42 răng)","aliases":["vòng răng thú","xâu chuỗi răng thú (42 răng)","Bảo Cụ của Bái Phong"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Thạch Hạo","Bái Phong"],"trangThai":"dang-co","blurb":"Xâu 42 răng thú trắng như mỡ dê đá ngọc, do Bảo cốt Tế linh làm thành, chí bảo của Bái thôn.","detail":"Bảo cụ gồm 42 cái răng thú trắng như mỡ dê đá ngọc, do Bảo cốt Tế linh làm thành. Có thể tụ tán, hóa thành hạt sáng, mưa sao băng, quái thú sói, vũ khí (chủy thủ, mũi tên) và chiến y; từng đâm thủng đá lớn 6-7 mét như cái sàng. Do Tế linh ban cho Bái thôn; khi Tế linh còn sống thì người được ban không cần Cốt văn cũng dùng được. Trong trận, 42 răng thú bị đánh rơi rụng rồi bị nhóc tỳ (Thạch Hạo) cướp và đeo lên cổ tay.","nguon":["@c0024"]},{"id":"xau-chuoi-rang-thu-nhoc-ty","name":"Xâu chuỗi răng thú","cn":"","category":"phap-bao","categoryLabel":"Bảo cụ","phamCap":"Bảo cụ khắc phù văn","soHuu":["Nhóc tỳ"],"trangThai":"Nhóc tỳ đang dùng","blurb":"Xâu 42 cái răng thú trắng đeo cổ tay nhóc tỳ, khắc phù văn, uy lực cực mạnh.","detail":"Bảo cụ gồm xâu chuỗi 42 cái răng thú trắng đeo ở cổ tay nhóc tỳ, được khắc phù văn. Khi vận dụng, các răng thú tách ra bay tán loạn như mưa ánh sáng, phóng hào quang trắng loáng xuyên thủng thân thể rất nhiều người, có thể hóa thành chủy thủ bắn ra mũi tên ánh sáng. Nhóc tỳ hiểu Cốt văn nên khi điều khiển Bảo cụ khiến uy lực mạnh mẽ hơn nhiều lần so với xâu răng thú từng ở trong tay Bái Phong. Trong trận đánh, nhóc tỳ dùng Bảo cụ này khai sát giới với người Bái thôn khiến chúng suy sụp bỏ chạy, đồng thời phối hợp với trăng bạc chém đám sói biến dị làm đôi.","nguon":["@c0025"]},{"id":"sung-do-di-chung-thai-co","name":"Sừng đỏ dị chủng Thái cổ","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Chiến lợi phẩm quý","soHuu":["Thạch thôn"],"trangThai":"Được dùng chữa trị Thanh Lân Ưng","blurb":"Sừng đỏ chót như ngọc của dị chủng Thái cổ, móc máu tươi cho Thanh Lân Ưng ăn để chữa thương.","detail":"Một cây sừng đỏ chót như ngọc, là chiến lợi phẩm thuộc dị chủng Thái cổ. Thạch Vân Phong dùng thuốc nhuyễn và móc máu tươi từ sừng đỏ này cho Thanh Lân Ưng ăn để chữa thương. Về sau nó được đội Thạch Phi Giao vận chuyển cùng các chiến lợi phẩm khác khi Thạch thôn rút quân.","nguon":["@c0025"]},{"id":"son-bao-thanh-vat","name":"Sơn bảo","aliases":["Thánh vật","Thần vật kinh thế"],"category":"khac","categoryLabel":"Bảo vật trục","phamCap":"Kinh thiên","soHuu":[],"trangThai":"dang-co","blurb":"Vật kinh thiên đang dựng dục nơi sâu Đại Hoang, khiến các siêu cấp đại tộc kéo tới tranh đoạt.","detail":"Sơn bảo (còn gọi Thánh vật, Thần vật) là vật kinh thiên đang được dựng dục nơi sâu Đại Hoang. Suốt hai năm, Di chủng Thái cổ tranh đoạt chưa ngã ngũ. Tin tức khiến bộ lạc Ngựa vảy sừng, vương hầu mặt trời tím, Tử Sơn hầu, Lôi Hậu và gia tộc cổ núi tuyết đều cử lớp trẻ đi kiến thức, mở màn xung đột lớn.","nguon":["@c0028"]},{"id":"thien-dia-bao-duoc","name":"Thiên địa bảo dược","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Truyền thuyết","soHuu":[],"trangThai":"khong-ro","blurb":"Thuốc quý trong truyền thuyết Thạch Hạo hứa hái để chữa ám thương cho tộc trưởng.","detail":"Loại thiên địa bảo dược cực hiếm mà trong dân số mấy triệu người chưa chắc có được. Thạch Hạo hứa sẽ tìm hái để trị tận gốc thương tật cổ quái của tộc trưởng Thạch Vân Phong.","nguon":["@c0029"]},{"id":"khoi-xuong-trang-thach-van-phong","name":"Khối xương trắng trước ngực","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Chưa rõ","soHuu":["Thạch Vân Phong"],"trangThai":"dang-co","blurb":"Vật thần bí tộc trưởng mang trước ngực, sờ vào thì thân run rẩy.","detail":"Khối xương trắng bạch tộc trưởng Thạch Vân Phong giữ trước ngực. Cuối chương lão sờ vào nó rồi bỗng run rẩy một cơn, có vẻ liên quan mật thiết tới ám thương cổ quái của ông.","nguon":["@c0029"]},{"id":"chan-huyet-bo-ma-ly-hoa","name":"Chân huyết Bò ma Ly Hỏa","category":"dan-duoc","categoryLabel":"Dược liệu","phamCap":"Không rõ","soHuu":["Thạch thôn"],"trangThai":"da-dung","blurb":"Chân huyết quý trong sừng Bò ma Ly Hỏa, dùng giải độc và khôi phục.","detail":"Chân huyết trong sừng quý của Ly Hỏa Ngưu Ma, có công dụng giải độc; được Thạch thôn dùng khôi phục cho Thanh Lân Ưng giúp nó hồi phục hoàn toàn.","nguon":["@c0033"]},{"id":"bao-cung-ten-sat-thien-tai","name":"Bảo cung và tên sắt hàn quang","category":"phap-bao","phamCap":"Vũ khí của thiên tài niên thiếu","soHuu":["Giao Bằng","Tử Sơn Côn","Lôi Minh Viễn"],"trangThai":"dang-co","blurb":"Bảo cung kèm tên sắt hàn quang lực xuyên thấu kinh người, dùng để săn thú.","detail":"Vũ khí các thiên tài niên thiếu La Phù Đại Trạch, Tử Sơn Tộc, Lôi Tộc mang theo để săn ba con chim non Thanh Lân Ưng của Thạch Thôn. Giao Bằng bắn liên châu tiễn khiến Đại Bằng và Tiểu Thanh trúng tên rụng vảy. Bảo cung của Tử Sơn Côn về sau bị đỉnh đồng ngàn cân Thạch Hạo đá văng đánh gãy đôi.","nguon":["@c0037"]},{"id":"dinh-den-to-truyen-thach-thon","name":"Đỉnh đen tổ truyền (Thạch thôn)","cn":"","aliases":["Bảo đỉnh chế thuốc","Đỉnh thuốc màu đen"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Chiếc đỉnh màu đen tổ tiên Thạch thôn truyền lại, khắc hình tiền dân Thượng cổ cùng nhật nguyệt sơn hà.","detail":"Bảo vật tổ truyền của Thạch thôn. Khi cả tộc mang tế phẩm tế bái dưới gốc cây liễu, chiếc đỉnh rung nhẹ, hình điêu khắc tiền dân Thượng cổ và nhật nguyệt sơn hà hiện rõ hơn, có ánh sáng yếu ớt vòng quanh. Người Thạch thôn dùng nó chế thuốc nhưng chưa hiểu hết uy năng thần bí.","nguon":["@c0041"]},{"id":"bao-cu-the-than-la-phu","name":"Khối xương thú (Bảo cụ thế thân)","cn":"","category":"phap-bao","categoryLabel":"Bảo cụ","phamCap":"Không rõ","soHuu":["Chủ nhân La Phù Đại Trạch"],"trangThai":"hong","blurb":"Bảo cụ thế thân bằng xương thú của tộc chủ La Phù Đại Trạch.","detail":"Khi bị cành liễu truy sát tới con sông phương Tây, tộc chủ La Phù Đại Trạch dùng khối xương thú làm bảo cụ thế thân để tránh đòn, nhưng bị chồi non đánh nát hóa thành vụn xương, sau đó chính hắn bị chém đứt làm hai.","nguon":["@c0044"]},{"id":"bao-cu-da-soi-vang","name":"Bảo Cụ da sói vàng","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Bảo Cụ","soHuu":[],"trangThai":"hong","blurb":"Tấm da màu vàng ra oai tấn công Thần Lang, bị cây liễu hủy diệt.","detail":"Một tấm da sói màu vàng dùng làm Bảo Cụ, xuất hiện trong cuộc tận diệt tứ đại cường giả để tấn công Thần Lang, nhưng lập tức bị cây liễu hủy chỉ trong nháy mắt.","nguon":["@c0045"]},{"id":"bao-cot-ngung-ky-hieu-nguyen-thuy","name":"Bảo cốt ngưng ký hiệu nguyên thủy","aliases":["Bảo cốt kỳ dị"],"category":"khac","categoryLabel":"Bảo vật","phamCap":"Thái Cổ","soHuu":[],"trangThai":"dang-co","blurb":"Hơn mười khúc xương thú kỳ dị ngưng ký hiệu nguyên thủy, rơi ra khi bốn sinh vật đại chiến, trấn áp Thương Mãng Sơn Mạch.","detail":"Trong trận đại chiến sâu trong dãy núi nguyên thủy, hơn mười khúc bảo cốt rơi ra: có khúc đỏ như Huyết Toản, có khúc đen như mực, có khúc trắng óng ánh. Đây là bảo cốt ngưng kết ký hiệu nguyên thủy, rơi từ Thái Cổ Di Chủng, phân tán khắp Thương Mãng Sơn Mạch để ổn định núi sông.","nguon":["@c0046"]},{"id":"bao-cot-nguyen-thuy-tran-nui","name":"Bảo cốt nguyên thủy (trấn áp)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Cực phẩm","soHuu":[],"trangThai":"hong","blurb":"Hơn mười mấy khối Bảo cốt nguyên thủy trấn áp dãy núi Thương Mãng, giữ sơn hà không bị đại chiến đánh tan hoang.","detail":"Nhờ hơn mười mấy khối Bảo cốt nguyên thủy trấn áp mà núi sông nơi tứ đại sinh linh huyết chiến không bị đánh tan hoang, phù văn sáng rực bao phủ dãy núi. Cuối chương Bảo cốt rốt cuộc không còn khóa nổi, khối Thánh vật xuyên phá phù văn, mở đường cho bốn sinh linh xông ra ngoài.","nguon":["@c0047"]}]};
